/**
 * GroundMaterialsService — port of Python SDK's `GroundMaterialsServiceClient`.
 *
 * Three public methods:
 *   - getRaw(lat, lon, distance, source?)              — single-point fetch
 *   - clean(layers, lat, lon, distance, default?)      — masking + bbox crop
 *   - getArea(polygon, opts?)                          — tile + fetch + merge
 *                                                        + clean pipeline
 *
 * NOTE: forge-kit's `@forge-kit/ground-materials` primitive is a different
 * package (drawing styles, registry, plugin UI) — this is the API service
 * client that mirrors Python's `GroundMaterialsServiceClient`. They are
 * complementary, not substitutes.
 */

import pLimit from 'p-limit'
import type { AuthResolver } from '../auth'
import { BigPayloadError, GroundMaterialsServiceError } from '../errors'
import { extractResponseBody, extractStatusCode, HttpClient } from '../http'
import type { Logger } from '../logger'
import { TileService } from '../tiling/tiles'
import { getNonEmptyTiles } from '../tiling/types'
import { arrayMax, arrayMin } from '../utils'
import { type GroundMaterialCleaner, RemoteCleaner, resolveCleaner } from './cleaner'

export interface GroundMaterialsServiceConfig {
  /** Auth header resolver — supports apiKey + JWT (token / getToken). */
  getAuthHeaders: AuthResolver
  baseUrl: string
  logger: Logger
  /** Request timeout in ms; default 300_000 (5 min). */
  timeout?: number
  /** Bare gateway URL for big-payload presign. Threaded from InfraredClient. */
  gatewayBaseUrl?: string
  /** Lazy big-payload kill switch — re-resolved per call. */
  getBigPayloadEnabled?: () => boolean
  /** Lazy big-payload threshold (bytes) — re-resolved per call. */
  getBigPayloadThresholdBytes?: () => number
}

/** GeoJSON FeatureCollection. */
export type FeatureCollection = {
  type?: string
  features?: Array<Record<string, unknown>>
  [key: string]: unknown
}

/** A dict of `layer_name -> FeatureCollection`. */
export type MaterialLayers = Record<string, FeatureCollection>

/** Aggregated result — mirrors Python `AreaGroundMaterials`. */
export interface AreaGroundMaterials {
  /** Cleaned material layers keyed by name (`'asphalt'`, `'vegetation'`, ...). */
  layers: MaterialLayers
  polygon: unknown
  totalFeatures: number
  executionTime: number
}

export interface IGroundMaterialsService {
  getRaw(
    lat: number,
    lon: number,
    distance: number,
    source?: string,
  ): Promise<MaterialLayers | null>
  clean(
    layers: MaterialLayers,
    lat: number,
    lon: number,
    distance: number,
    defaultMaterial?: string,
  ): Promise<MaterialLayers | null>
  getArea(
    polygon: unknown,
    opts?: {
      maxWorkers?: number
      defaultMaterial?: string
      maxTilesOverride?: number
      /** Which clean-v3 backend to use. Default 'remote' (the gateway call).
       *  'local' = pure client-side port; a custom object = worker/WASM bridge. */
      cleaner?: 'remote' | 'local' | GroundMaterialCleaner
      /** z-step for local/custom cleaners (ignored by 'remote'). Default 0.00001. */
      zStep?: number
    },
  ): Promise<AreaGroundMaterials>
}

const TILE_FETCH_DISTANCE_M = Math.ceil(Math.sqrt(2) * 256)
const DEFAULT_MATERIAL = 'asphalt'
// fgb (Overture + road-surface FlatGeobuf) is the default ground-material
// source; Mapbox is retained only as an explicit `source: 'mapbox'` opt-in.
// Matches `vegetation/service.ts` (already 'fgb') and the server default
// (`GET /ground-material/collect` defaults to fgb). Inherited by both `getRaw`
// and the tiled `getArea` (which calls `getRaw` without a source arg).
const DEFAULT_SOURCE = 'fgb'
const METERS_PER_DEG_LAT = 111_320

export class GroundMaterialsService implements IGroundMaterialsService {
  private httpClient: HttpClient
  private logger: Logger

  constructor(config: GroundMaterialsServiceConfig) {
    this.httpClient = new HttpClient({
      getAuthHeaders: config.getAuthHeaders,
      baseUrl: config.baseUrl,
      logger: config.logger,
      timeout: config.timeout ?? 300_000,
      gatewayBaseUrl: config.gatewayBaseUrl,
      getBigPayloadEnabled: config.getBigPayloadEnabled,
      getBigPayloadThresholdBytes: config.getBigPayloadThresholdBytes,
    })
    this.logger = config.logger
  }

  async getRaw(
    lat: number,
    lon: number,
    distance: number,
    source: string = DEFAULT_SOURCE,
  ): Promise<MaterialLayers | null> {
    try {
      const data = await this.httpClient.get<MaterialLayers & { error?: string; traceback?: string }>(
        '/ground-material/collect',
        { latitude: lat, longitude: lon, distance, source },
      )
      if (!data) return null
      if (data.error && data.traceback) {
        // Server returned a JSON error envelope (HTTP 200 with body=error).
        // Surface as a typed error so callers can catch + inspect.
        throw new GroundMaterialsServiceError(
          `Ground materials collect error at (${lat}, ${lon}): ${data.error}`,
          { statusCode: 0, responseBody: data.traceback ?? '', operation: 'getRaw' },
        )
      }
      // Strip API error envelope keys defensively before returning
      const { error: _e, traceback: _t, ...layers } = data as Record<string, unknown>
      void _e
      void _t
      return layers as MaterialLayers
    } catch (err) {
      if (err instanceof GroundMaterialsServiceError) throw err
      throw new GroundMaterialsServiceError(
        `Ground materials collect failed at (${lat}, ${lon}): ${err instanceof Error ? err.message : String(err)}`,
        {
          statusCode: extractStatusCode(err),
          responseBody: extractResponseBody(err),
          operation: 'getRaw',
        },
      )
    }
  }

  async clean(
    layers: MaterialLayers,
    lat: number,
    lon: number,
    distance: number,
    defaultMaterial: string = DEFAULT_MATERIAL,
  ): Promise<MaterialLayers | null> {
    try {
      // Delegates to RemoteCleaner — the one code path for the gateway call.
      // (Micro-diff vs. the pre-delegation code: the near-unreachable falsy-body
      // branch returns `{}` instead of `null`; callers treat both as "nothing".)
      const cleaner = new RemoteCleaner({ httpClient: this.httpClient })
      return await cleaner.cleanV3(layers, {
        latitude: lat,
        longitude: lon,
        distance,
        defaultLayer: defaultMaterial,
      })
    } catch (err) {
      if (err instanceof GroundMaterialsServiceError) throw err
      throw new GroundMaterialsServiceError(
        `Ground materials clean failed at (${lat}, ${lon}): ${err instanceof Error ? err.message : String(err)}`,
        {
          statusCode: extractStatusCode(err),
          responseBody: extractResponseBody(err),
          operation: 'clean',
        },
      )
    }
  }

  async getArea(
    polygon: unknown,
    opts: {
      maxWorkers?: number
      defaultMaterial?: string
      maxTilesOverride?: number
      cleaner?: 'remote' | 'local' | GroundMaterialCleaner
      zStep?: number
    } = {},
  ): Promise<AreaGroundMaterials> {
    const t0 = performance.now()
    const maxWorkers = opts.maxWorkers ?? 10
    const defaultMaterial = opts.defaultMaterial ?? DEFAULT_MATERIAL

    // 1. Generate tiles
    const svc = new TileService({
      polygon,
      maxTilesOverride: opts.maxTilesOverride,
    })
    const grid = svc.generateTilesForPolygon()
    const nonEmpty = getNonEmptyTiles(grid)
    this.logger.info(
      `getArea: ${nonEmpty.length} non-empty tile(s); fetching Mapbox land-cover ` +
        `via /ground-material/collect (parallel, up to ${maxWorkers} workers)`,
    )

    // 2. Fetch raw layers per tile centroid in parallel. Per-tile failures
    // soft-fail to null (logged) so a single 502 doesn't kill the whole
    // pipeline — matches Python's `executor.execute` behaviour.
    const limit = pLimit(maxWorkers)
    const fetchTasks = nonEmpty.map(({ tile }) =>
      limit(async () => {
        try {
          return await this.getRaw(
            tile.centroid.latitude,
            tile.centroid.longitude,
            TILE_FETCH_DISTANCE_M,
          )
        } catch (err) {
          this.logger.warn(
            `Ground-materials tile ${tile.tileId} failed: ${err instanceof Error ? err.message : 'unknown'}`,
          )
          return null
        }
      }),
    )
    const tileResults = await Promise.all(fetchTasks)

    // 3. Merge per-layer + dedup across overlapping tiles
    let mergedLayers = mergeTileLayers(tileResults)
    this.logger.info(
      `merged ${Object.keys(mergedLayers).length} layer(s) across tiles; ` +
        `calling /ground-material/clean-v3`,
    )

    if (Object.keys(mergedLayers).length === 0) {
      this.logger.info('No ground materials found in area')
      const elapsed = (performance.now() - t0) / 1000
      return {
        layers: {},
        polygon,
        totalFeatures: 0,
        executionTime: elapsed,
      }
    }

    // 4. Compute polygon-bounding-circle params for /clean
    const ring = (polygon as { coordinates?: number[][][] }).coordinates?.[0] ?? []
    if (ring.length > 0) {
      const lons = ring.map((pt) => pt[0])
      const lats = ring.map((pt) => pt[1])
      const minLat = arrayMin(lats)
      const maxLat = arrayMax(lats)
      const minLon = arrayMin(lons)
      const maxLon = arrayMax(lons)
      const centerLat = (minLat + maxLat) / 2.0
      const centerLon = (minLon + maxLon) / 2.0
      const latSpanM = (maxLat - minLat) * METERS_PER_DEG_LAT
      const lonSpanM = (maxLon - minLon) * METERS_PER_DEG_LAT * Math.cos((centerLat * Math.PI) / 180)
      const approxDistance = Math.sqrt(latSpanM * latSpanM + lonSpanM * lonSpanM) / 2.0

      // Every cleaner receives identical inputs (same bounding-circle params) →
      // identical crop bbox. Default 'remote' keeps behaviour unchanged.
      const cleaner = resolveCleaner(opts.cleaner ?? 'remote', { httpClient: this.httpClient })
      try {
        const cleaned = await cleaner.cleanV3(mergedLayers, {
          latitude: centerLat,
          longitude: centerLon,
          distance: Math.max(approxDistance, TILE_FETCH_DISTANCE_M),
          defaultLayer: defaultMaterial,
          zStep: opts.zStep,
        })
        // Replace only on a non-empty cleaned result. RemoteCleaner returns
        // `{}` on the near-unreachable falsy-body case; treating that as "keep
        // merged" matches Python `_clean` returning None → `if cleaned is not
        // None` skipping the replacement.
        if (cleaned && Object.keys(cleaned).length > 0) mergedLayers = cleaned
      } catch (err) {
        // Parity with Python `_clean`: HTTP/error-body/generic clean failures
        // soft-fail to the merged-but-uncleaned layers (the tile-fetch loop
        // soft-fails the same way) — but BigPayloadError (presign/upload/REF_*
        // infra failures) MUST propagate per the typed-exception contract.
        if (err instanceof BigPayloadError) throw err
        this.logger.warn(
          `Ground-materials clean failed; returning uncleaned merged layers: ${err instanceof Error ? err.message : 'unknown'}`,
        )
      }
    }

    const totalFeatures = Object.values(mergedLayers).reduce(
      (sum, fc) => sum + (fc.features?.length ?? 0),
      0,
    )
    const elapsed = (performance.now() - t0) / 1000

    this.logger.info(
      `Ground materials pipeline: ${totalFeatures} features, ` +
        `${Object.keys(mergedLayers).length} layers, ${nonEmpty.length} tiles, ` +
        `${elapsed.toFixed(1)}s`,
    )

    return {
      layers: mergedLayers,
      polygon,
      totalFeatures,
      executionTime: elapsed,
    }
  }
}

// ---------------------------------------------------------------------------
// Dedup — mirrors Python `ground_materials/dedup.py`
// ---------------------------------------------------------------------------

/**
 * Stable identity for a GeoJSON Feature, derived from its geometry. Used
 * to deduplicate features fetched from overlapping tiles.
 *
 * Python uses md5(canonical_json(geometry)). Md5 needs `crypto.subtle`
 * (async) in browsers/Workers; we use the canonical JSON string itself
 * as the key, which is correctness-equivalent and synchronous. Memory
 * cost is bounded by tile feature counts (typically < 10k per area).
 */
function featureIdentity(feature: Record<string, unknown>): string {
  const geom = (feature.geometry as Record<string, unknown> | undefined) ?? {}
  return canonicalJson(geom)
}

function canonicalJson(value: unknown): string {
  if (value === null || value === undefined) return JSON.stringify(value)
  if (typeof value !== 'object' || Array.isArray(value)) return JSON.stringify(value)
  const obj = value as Record<string, unknown>
  const keys = Object.keys(obj).sort()
  const inner = keys.map((k) => `${JSON.stringify(k)}:${canonicalJson(obj[k])}`).join(',')
  return `{${inner}}`
}

/**
 * Merge per-layer GeoJSON features across tiles, deduplicating by
 * geometry. Mirrors Python's `merge_tile_layers`.
 */
function mergeTileLayers(
  tileResults: ReadonlyArray<MaterialLayers | null>,
): MaterialLayers {
  const layerFeatures: Record<string, Map<string, Record<string, unknown>>> = {}

  for (const tileLayers of tileResults) {
    if (!tileLayers) continue
    for (const [layerName, fc] of Object.entries(tileLayers)) {
      const features = fc?.features ?? []
      if (features.length === 0) continue
      if (!(layerName in layerFeatures)) layerFeatures[layerName] = new Map()
      const seen = layerFeatures[layerName]
      for (const feature of features) {
        const id = featureIdentity(feature)
        if (!seen.has(id)) seen.set(id, feature)
      }
    }
  }

  const out: MaterialLayers = {}
  for (const [layerName, seen] of Object.entries(layerFeatures)) {
    out[layerName] = {
      type: 'FeatureCollection',
      features: Array.from(seen.values()),
    }
  }
  return out
}

export { GroundMaterialsServiceError }
