// ---------------------------------------------------------------------------
// Constants
// ---------------------------------------------------------------------------

/**
 * Polling backoff constants for area-level wait. Mirrors Python SDK
 * `_area/_polling.py` (`_POLL_BACKOFF_BASE=2`, `_POLL_BACKOFF_CAP=10`,
 * `_POLL_BACKOFF_FLOOR=0.5`). Pre-0.4.7 the TS port had cap=60 / floor=1.0;
 * those values produced longer-than-necessary polling waits versus Python.
 */
const POLL_BACKOFF_BASE = 2
const POLL_BACKOFF_CAP = 10
const POLL_BACKOFF_FLOOR = 0.5

/** Default fallback base URL — matches Python SDK's DEFAULT_BASE_URL. */
const DEFAULT_BASE_URL = 'https://api.infrared.city/v2'

/** Maximum concurrent tile submissions in runArea. Caps subrequests on Workers. */
const MAX_PARALLEL_SUBMISSIONS = 8

/**
 * Concurrency cap for per-job status queries inside a single
 * `checkAreaState` call. Mirrors Python `_DEFAULT_MAX_WORKERS=5` in
 * `_area/_polling.py`. Stops a 50-tile area from spraying 50 parallel
 * GETs at the status endpoint on every poll round.
 */
const STATUS_MAX_WORKERS = 5

/**
 * Per-call retry budget for a single job's status query. Mirrors Python
 * `_STATUS_RETRY_MAX=5` in `_area/_polling.py` — the loop runs
 * `range(STATUS_RETRY_MAX + 1)`, so this yields 6 total attempts before
 * the job is considered failed-for-this-round and the wedge counter
 * (`MAX_CONSECUTIVE_POLL_FAILURES`) is incremented.
 */
const STATUS_RETRY_MAX = 5

/** HTTP status codes considered retryable. Matches `http.ts` and Python `_is_retryable`. */
const POLL_RETRYABLE_STATUS_CODES = new Set([429, 500, 502, 503, 504])

/**
 * After this many consecutive failed status polls for the same job
 * (each already retried up to `STATUS_RETRY_MAX` times internally),
 * `checkAreaState` marks the job as `skipped` so the polling loop in
 * `runAreaAndWait` cannot wedge waiting on a job whose status endpoint
 * is permanently broken. This is defense-in-depth beyond Python SDK,
 * which has no cross-round wedge counter and relies solely on the
 * area-level timeout.
 */
const MAX_CONSECUTIVE_POLL_FAILURES = 5

/**
 * True iff this error should be retried by `checkAreaState`. Mirrors
 * Python `tiling/executor.py::_is_retryable`: any error carrying a
 * `statusCode` in {429, 500, 502, 503, 504}, or an `AbortError`
 * (timeout), or an `InfraredError` with `statusCode === 0` (the SDK's
 * timeout convention from `jobs/service.ts`).
 */
function isRetryablePollError(err: unknown): boolean {
  if (!err || typeof err !== 'object') return false
  const e = err as { statusCode?: unknown; name?: unknown }
  if (e.name === 'AbortError') return true
  if (typeof e.statusCode === 'number') {
    if (e.statusCode === 0) return true // SDK timeout convention
    return POLL_RETRYABLE_STATUS_CODES.has(e.statusCode)
  }
  return false
}

/**
 * Compute the per-attempt sleep for the polling-layer retry around a
 * single `getStatus` call. Honors `retryAfter` (carried on
 * `JobPollError`) when present; falls back to full-jitter backoff with
 * the same shape as Python `_compute_retry_delay_simple` and
 * `submitWithRetry` above.
 */
function computePollRetryDelay(attempt: number, err: unknown): number {
  const retryAfter = (err as { retryAfter?: unknown } | null)?.retryAfter
  if (typeof retryAfter === 'number' && Number.isFinite(retryAfter) && retryAfter >= 0) {
    return retryAfter
  }
  const cap = Math.min(SUBMIT_BACKOFF_CAP, SUBMIT_BACKOFF_BASE * 2 ** attempt)
  return Math.max(SUBMIT_BACKOFF_FLOOR, Math.random() * cap)
}

/** Retry shape for transient errors during job submission / download. */
const SUBMIT_MAX_ATTEMPTS = 3 // initial + 2 retries
const SUBMIT_BACKOFF_BASE = 2
const SUBMIT_BACKOFF_CAP = 10
const SUBMIT_BACKOFF_FLOOR = 0.5

/**
 * Retry helper mirroring Python SDK's submission backoff
 * (`_submit_with_retry`). Retries up to SUBMIT_MAX_ATTEMPTS - 1 times on any
 * thrown error from `fn`; sleeps with exponential backoff plus jitter between
 * attempts.
 *
 * 402 (insufficient credits) is non-retryable and account-global — rethrow
 * immediately as `InsufficientCreditsError` without consuming retry budget.
 */
async function submitWithRetry<T>(
  fn: () => Promise<T>,
  logger: Logger,
  tileId: string,
): Promise<T> {
  let lastError: unknown
  for (let attempt = 0; attempt < SUBMIT_MAX_ATTEMPTS; attempt++) {
    try {
      return await fn()
    } catch (err) {
      // 402 is account-global — no point retrying any tile; rethrow immediately.
      if (
        err instanceof InsufficientCreditsError ||
        (err as { statusCode?: number }).statusCode === 402
      ) {
        throw err instanceof InsufficientCreditsError
          ? err
          : new InsufficientCreditsError(
              err instanceof Error ? err.message : String(err),
              { responseBody: (err as { responseBody?: string }).responseBody ?? '' },
            )
      }
      lastError = err
      if (attempt === SUBMIT_MAX_ATTEMPTS - 1) break
      const cap = Math.min(SUBMIT_BACKOFF_CAP, SUBMIT_BACKOFF_BASE ** (attempt + 1))
      const delay = Math.max(SUBMIT_BACKOFF_FLOOR, Math.random() * cap)
      logger.warn(
        `submit retry ${attempt + 1}/${SUBMIT_MAX_ATTEMPTS - 1} for tile ${tileId} ` +
          `after ${delay.toFixed(2)}s: ${err}`,
      )
      await new Promise((resolve) => setTimeout(resolve, delay * 1000))
    }
  }
  throw lastError
}

// ---------------------------------------------------------------------------
// Config
// ---------------------------------------------------------------------------

/**
 * Worker bindings shape — anything with `INFRARED_API_KEY` and optional
 * `INFRARED_BASE_URL` keys (e.g. Cloudflare Workers `env` object). Also
 * carries the big-payload kill switch / threshold env vars.
 */
export interface InfraredEnvBindings extends BigPayloadEnvBindings {
  INFRARED_API_KEY?: string
  INFRARED_BASE_URL?: string
}

export interface InfraredClientConfig {
  /**
   * API key for authentication. Falls back to `env.INFRARED_API_KEY` then to
   * `process.env.INFRARED_API_KEY` (Node only). Sent as `X-Api-Key` header
   * on every request. May coexist with `token` / `getToken` (gateway
   * authenticates the JWT, downstream Lambdas read `X-Api-Key`).
   */
  apiKey?: string
  /**
   * Static JWT bearer token. Sent as `Authorization: Bearer <token>` on
   * every request. Use for long-lived service tokens. Mutually exclusive
   * with `getToken`.
   */
  token?: string
  /**
   * Dynamic JWT bearer resolver. Called on **every** request — right
   * pattern for browser / Worker contexts where tokens expire and the app
   * refreshes them out-of-band. Mutually exclusive with `token`.
   */
  getToken?: () => string | Promise<string>
  /**
   * Base URL for the API. Falls back to `env.INFRARED_BASE_URL`, then
   * `process.env.INFRARED_BASE_URL`, then `https://api.infrared.city/v2`.
   */
  baseUrl?: string
  /**
   * Cloudflare Worker bindings (or any object) carrying `INFRARED_API_KEY` /
   * `INFRARED_BASE_URL`. Workers don't expose `process.env`, so pass `env`
   * here.
   */
  env?: InfraredEnvBindings
  logger?: Logger
  /**
   * Control-plane request timeout in ms (submit / poll / status / utility).
   * Default 180_000 (3 min). Mirrors Python SDK's `(10, 300)` read budget.
   */
  timeout?: number
  /**
   * S3 result-download timeout in ms (presigned-URL fetch in `downloadResults`).
   * Default 600_000 (10 min). Larger than `timeout` because cold-Lambda S3
   * fetches of full-year weather payloads stream slowly; matches Python SDK's
   * `S3_TIMEOUT_S = (10, 600)`.
   */
  downloadTimeout?: number
  /** Pre-configured JobsService instance (for DI / testing). */
  jobsService?: IJobsService
  /** Pre-configured AnalysisService instance (for DI / testing). */
  analysisService?: IAnalysisService
  /** Pre-configured WeatherService instance (for DI / testing). */
  weatherService?: IWeatherService
  /** Pre-configured VegetationService instance (for DI / testing). */
  vegetationService?: IVegetationService
  /** Pre-configured GroundMaterialsService instance (for DI / testing). */
  groundMaterialsService?: IGroundMaterialsService
  /** Pre-configured BuildingsService instance (for DI / testing). */
  buildingsService?: IBuildingsService
  /** Pre-configured WebhooksService instance (for DI / testing). */
  webhooksService?: IWebhooksService
  /** Pre-configured BillingService instance (for DI / testing). */
  billingService?: IBillingService
  /**
   * Big-payload flow overrides. When set, short-circuits env-var resolution.
   * `enabled=false` forces inline path even above threshold; `thresholdBytes`
   * tunes the cut-over (default 5 MiB). Service clients route their large
   * POSTs (buildings, vegetation, ground-materials, weather generate-image,
   * filter, analyses jobs) through the auto-switching `$ref` envelope flow
   * that mirrors Python SDK 0.4.4. Both can also be set via env vars
   * `INFRARED_BIG_PAYLOADS_ENABLED` / `INFRARED_BIG_PAYLOADS_THRESHOLD_BYTES`.
   */
  bigPayloads?: BigPayloadOverride
  /**
   * Bare gateway URL for the big-payload presign endpoint
   * (`{gateway}/uploads/presign`). Defaults to
   * `deriveGatewayBaseUrl(baseUrl)` (strips trailing `/utils`). Override only
   * if the gateway lives at a different host than `baseUrl`.
   */
  gatewayBaseUrl?: string
}

/**
 * Options for `runArea` / `runAreaAndWait`. Mirrors the keyword-only
 * surface of Python SDK's `run_area`:
 *
 *   buildings / vegetation / ground_materials  layer maps to inject per-tile.
 *   max_tiles_override                         override the non-empty tile cap.
 *   max_workers                                concurrency cap for submit.
 *   webhook_url / webhook_events               optional async webhook hook.
 *   retry_from                                 only resubmit tiles in the
 *                                              failed_submissions list of a
 *                                              prior schedule.
 */
export interface RunAreaOptions {
  /**
   * Buildings hint. Pass any non-empty dict to trigger the
   * `BuildingsService.getBuildingsByTiles` server-side fetch path.
   * (Per-tile pre-supplied buildings will land in v0.7.)
   */
  buildings?: Record<string, unknown>
  /**
   * Vegetation features keyed by stable feature ID (typically the dict
   * returned from `client.vegetation.getArea(polygon)` `.features` field).
   * Each feature is assigned to every tile whose bbox contains its centroid.
   * Pass `undefined` or `{}` to skip vegetation injection (server runs without
   * tree shading).
   */
  vegetation?: Record<string, Record<string, unknown>>
  /**
   * Ground-material layers (`{ layerName: FeatureCollection }`), typically
   * the `.layers` field returned from `client.groundMaterials.getArea(polygon)`.
   * Each feature is assigned to every tile whose bbox overlaps its bbox.
   * Pass `undefined` or `{}` to skip ground-material injection.
   */
  groundMaterials?: Record<string, { features?: Array<Record<string, unknown>> }>
  /** Override the default non-empty-tile cap (`MAX_NON_EMPTY_TILES`). */
  maxTilesOverride?: number
  /** Concurrent submit cap. Defaults to `MAX_PARALLEL_SUBMISSIONS` (8). */
  maxWorkers?: number
  /** Optional webhook URL to register on each submitted job. */
  webhookUrl?: string
  /** Webhook events to subscribe (default: `['job.succeeded', 'job.failed']`). */
  webhookEvents?: string[]
  /**
   * Retry mode — when supplied, only tiles in
   * `retryFrom.failedSubmissions` are resubmitted. Other tiles are skipped.
   */
  retryFrom?: AreaSchedule
}

/** Read an env var across Node / Workers without breaking Worker compat. */
function readEnvVar(env: InfraredEnvBindings | undefined, key: keyof InfraredEnvBindings): string | undefined {
  if (env && env[key]) return env[key]
  // Workers have no `process`; guard via globalThis so the bundler doesn't
  // emit a runtime reference.
  const proc = (globalThis as { process?: { env?: Record<string, string | undefined> } }).process
  return proc?.env?.[key]
}

// ---------------------------------------------------------------------------
// Client
// ---------------------------------------------------------------------------

/**
 * Main Infrared SDK client.
 *
 * Provides high-level methods for single-tile and area-level analysis,
 * building data retrieval, and webhook management.
 */
export class InfraredClient {
  /**
   * Resolved API key (if provided). `undefined` when the client was built
   * with JWT auth only. Exposed as `readonly` for consumers that need to
   * forward the key to non-SDK code paths.
   */
  public readonly apiKey: string | undefined
  public readonly baseUrl: string
  public readonly jobs: IJobsService
  public readonly analyses: IAnalysisService
  public readonly weather: IWeatherService
  public readonly vegetation: IVegetationService
  public readonly groundMaterials: IGroundMaterialsService
  public readonly buildings: IBuildingsService
  /**
   * Per-job count of consecutive `checkAreaState` poll failures. When the
   * count exceeds `MAX_CONSECUTIVE_POLL_FAILURES`, the job is marked
   * `skipped` so the wait loop unblocks instead of hanging until timeout.
   */
  private readonly pollFailureCounts = new Map<string, number>()
  public readonly webhooks: IWebhooksService
  /**
   * Public billing/pricing reads (`GET {gateway}/billing/pricing`, no auth).
   * Backs `previewAreaWithPricing()`; usable directly for raw pricing data.
   */
  public readonly billing: IBillingService

  /** Bare gateway URL for big-payload presign (`{gateway}/uploads/presign`). */
  public readonly gatewayBaseUrl: string
  /**
   * Live big-payload kill switch — re-resolves env / override on every
   * read. Use the getter form (`bigPayloadEnabled`) to observe current
   * state; the boolean property below is kept for back-compat, snapshots
   * the value at construction, and **does not** see env-var flips.
   */
  public get bigPayloadEnabled(): boolean {
    return this.getBigPayloadEnabled()
  }
  /** Live big-payload threshold in bytes — re-resolves env / override per read. */
  public get bigPayloadThresholdBytes(): number {
    return this.getBigPayloadThresholdBytes()
  }

  /** Live resolvers — closures over `env` + `override`. Re-read on each call. */
  private readonly getBigPayloadEnabled: () => boolean
  private readonly getBigPayloadThresholdBytes: () => number
  private readonly getAuthHeaders: AuthResolver

  private readonly logger: Logger

  constructor(config: InfraredClientConfig = {}) {
    this.logger = config.logger ?? consoleLogger

    // Resolve apiKey: explicit arg > env (Worker bindings) > process.env (Node).
    const apiKey = config.apiKey ?? readEnvVar(config.env, 'INFRARED_API_KEY')
    this.apiKey = apiKey

    // Build the auth resolver. Validates `token`/`getToken` mutual
    // exclusion and at-least-one-auth — throws with a useful message if
    // none are provided. Resolves headers per request, so JWT refresh
    // (`getToken`) lands fresh tokens on every call.
    this.getAuthHeaders = buildAuthResolver({
      apiKey,
      token: config.token,
      getToken: config.getToken,
    })

    // Resolve baseUrl: explicit arg > env > process.env > DEFAULT_BASE_URL.
    this.baseUrl =
      config.baseUrl ?? readEnvVar(config.env, 'INFRARED_BASE_URL') ?? DEFAULT_BASE_URL

    // Big-payload knobs: build closures over `env` + override so they
    // re-read on every call. Snapshotting at construction violated the
    // documented "read on every call" contract — notebook users that
    // flip `INFRARED_BIG_PAYLOADS_ENABLED` mid-session now see the new
    // value immediately.
    const env = config.env
    const enabledOverride = config.bigPayloads?.enabled
    const thresholdOverride = config.bigPayloads?.thresholdBytes
    this.getBigPayloadEnabled = () => readEnabled(env, enabledOverride)
    this.getBigPayloadThresholdBytes = () =>
      readThresholdBytes(env, thresholdOverride)

    this.gatewayBaseUrl = config.gatewayBaseUrl ?? deriveGatewayBaseUrl(this.baseUrl)

    this.logger.debug({ event: 'client_init', baseUrl: this.baseUrl })

    // Initialize JobsService — big-payloads thread through to enable
    // auto-switching `application/zip` envelope for >5 MiB analyses payloads.
    this.jobs =
      config.jobsService ??
      new JobsService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: this.baseUrl,
        logger: this.logger,
        timeout: config.timeout,
        downloadTimeout: config.downloadTimeout,
        gatewayBaseUrl: this.gatewayBaseUrl,
        getBigPayloadEnabled: this.getBigPayloadEnabled,
        getBigPayloadThresholdBytes: this.getBigPayloadThresholdBytes,
      })

    // Initialize AnalysisService
    this.analyses =
      config.analysisService ??
      new AnalysisService({
        logger: this.logger,
        jobsService: this.jobs,
      })

    // Initialize WeatherService (Python: WeatherServiceClient, exposed as
    // client.weather; was previously named UtilityService / client.utilities)
    this.weather =
      config.weatherService ??
      new WeatherService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: `${this.baseUrl}/utils`,
        logger: this.logger,
        timeout: config.timeout,
        gatewayBaseUrl: this.gatewayBaseUrl,
        getBigPayloadEnabled: this.getBigPayloadEnabled,
        getBigPayloadThresholdBytes: this.getBigPayloadThresholdBytes,
      })

    // Initialize VegetationService (Python: VegetationServiceClient).
    // Shares the /utils base path with weather since both endpoints
    // (/gis/vegetation, /convert/geojson-to-mesh) live under the
    // utilities API.
    this.vegetation =
      config.vegetationService ??
      new VegetationService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: `${this.baseUrl}/utils`,
        logger: this.logger,
        timeout: config.timeout,
        gatewayBaseUrl: this.gatewayBaseUrl,
        getBigPayloadEnabled: this.getBigPayloadEnabled,
        getBigPayloadThresholdBytes: this.getBigPayloadThresholdBytes,
      })

    // Initialize GroundMaterialsService (Python: GroundMaterialsServiceClient).
    // Endpoints /ground-material/collect and /ground-material/clean-v3 also
    // live under the /utils base path.
    this.groundMaterials =
      config.groundMaterialsService ??
      new GroundMaterialsService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: `${this.baseUrl}/utils`,
        logger: this.logger,
        timeout: config.timeout,
        gatewayBaseUrl: this.gatewayBaseUrl,
        getBigPayloadEnabled: this.getBigPayloadEnabled,
        getBigPayloadThresholdBytes: this.getBigPayloadThresholdBytes,
      })

    // Initialize BuildingsService
    this.buildings =
      config.buildingsService ??
      new BuildingsService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: this.baseUrl,
        logger: this.logger,
        timeout: config.timeout,
        gatewayBaseUrl: this.gatewayBaseUrl,
        getBigPayloadEnabled: this.getBigPayloadEnabled,
        getBigPayloadThresholdBytes: this.getBigPayloadThresholdBytes,
      })

    // Initialize WebhooksService
    this.webhooks =
      config.webhooksService ??
      new WebhooksService({
        getAuthHeaders: this.getAuthHeaders,
        baseUrl: this.baseUrl,
        logger: this.logger,
        timeout: config.timeout,
      })

    // Initialize BillingService — needs the resolved gatewayBaseUrl above.
    // The pricing endpoint is public, so no auth resolver is threaded in.
    this.billing =
      config.billingService ??
      new BillingService({
        gatewayBaseUrl: this.gatewayBaseUrl,
        logger: this.logger,
        timeout: config.timeout,
      })
  }

  // -------------------------------------------------------------------------
  // Cleanup
  // -------------------------------------------------------------------------

  /**
   * Release owned resources. Safe to call multiple times.
   */
  close(): void {
    this.logger.debug({ event: 'client_close' })
  }

  // -------------------------------------------------------------------------
  // Single-tile helpers (private)
  // -------------------------------------------------------------------------

  /**
   * Transform an AnalysisInput into a kebab-case payload ready for the API,
   * preserving camelCase for wind-data as the backend expects.
   */
  private preparePayload(input: AnalysisInput): {
    analysisType: string
    serialized: Record<string, unknown>
  } {
    const payload = transformAnalysisInput(input)
    const analysisType = payload.analysisType
    const serialized = serializeToKebab(payload) as Record<string, unknown>

    // Preserve camelCase for wind-data as backend expects it
    if (serialized['wind-data']) {
      serialized['wind-data'] = deserializeToCamelCase(serialized['wind-data'])
    }

    return { analysisType, serialized }
  }

  // -------------------------------------------------------------------------
  // run -- single-tile job submission
  // -------------------------------------------------------------------------

  /**
   * Submit a single-tile analysis job and return the Job handle.
   *
   * @param input - Analysis input configuration.
   * @param opts - Optional webhook configuration.
   * @returns The submitted job.
   */
  async run(
    input: AnalysisInput,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<Job> {
    return this.analyses.execute(input, opts)
  }

  // -------------------------------------------------------------------------
  // runAndWait -- single-tile, blocking
  // -------------------------------------------------------------------------

  /**
   * Submit a single-tile analysis, wait for completion, return decompressed results.
   *
   * Return type is inferred from `input.analysisType` via `InferAnalysisResponse<T>`,
   * so callers get a precisely-typed response (`WindSpeedResponse`,
   * `SolarAnalysisResponse`, etc.) without needing `as`.
   *
   * @param input - Analysis input configuration.
   * @param timeout - Timeout in seconds (default 300).
   * @param opts - Optional webhook configuration.
   */
  async runAndWait<T extends AnalysisInput>(
    input: T,
    timeout = 300,
    opts?: { webhookUrl?: string; webhookEvents?: string[] },
  ): Promise<InferAnalysisResponse<T>> {
    const job = await this.analyses.execute(input, opts)
    const completed = await this.jobs.waitForCompletion(job.jobId, { timeout })
    const download = await this.jobs.downloadResults(completed.jobId, { job: completed })
    return this.jobs.decompress(download.content) as unknown as InferAnalysisResponse<T>
  }

  // -------------------------------------------------------------------------
  // previewArea -- tile count preview
  // -------------------------------------------------------------------------

  /**
   * Preview tiling for a polygon without running any analyses.
   *
   * Uses TileService internally -- no API call, just tile grid calculation.
   * Wind analyses tile at 50% overlap (256m step); solar / UTCI / daylight /
   * SVF / TCS tile edge-to-edge (512m step) — so the SAME polygon produces
   * up to ~4× more wind tiles than solar tiles. `analysisType` is therefore
   * required: the tile count (and cost estimate) only matches what `runArea`
   * will submit — and what the gateway will charge — when it is the same
   * analysis type you pass to `runArea`.
   *
   * Cost semantics: the gateway charges a flat per-job token price at
   * submission time (`estimatedCostTokens = tileCount × tokensPerJob`).
   * Tiles whose submission FAILS are never charged, so the actual charge is
   * always ≤ the estimate. This method uses the offline fallback price
   * (`DEFAULT_TOKENS_PER_JOB`); use `previewAreaWithPricing()` for a quote
   * based on the gateway's live pricing document.
   *
   * @param polygon - A GeoJSON Polygon object.
   * @param opts.analysisType - Analysis type the preview should size for.
   *   Required at the type level. At runtime a missing value logs a warning
   *   and falls back to wind tiling (pre-0.12 behavior) — which OVERCOUNTS
   *   solar-family analyses ~4×.
   * @param opts.maxTilesOverride - Optional override for the non-empty tile cap.
   * @returns Preview with tile count, estimated time, and estimated cost.
   * @throws Error if `analysisType` is not supported for tiling (same guard
   *   as `runArea`).
   */
  previewArea(
    polygon: unknown,
    opts: { analysisType: AnalysesName; maxTilesOverride?: number },
  ): AreaPreview {
    const validated = validatePolygon(polygon)

    // Runtime stays lenient for compiled-JS callers that predate the
    // required-opts signature: warn loudly, keep the historical wind default.
    const analysisType = opts?.analysisType
    if (analysisType === undefined) {
      this.logger.warn({
        event: 'preview_area_no_analysis_type',
        message:
          'previewArea called without analysisType; defaulting to wind tiling ' +
          '(256 m step). Solar / daylight / thermal / SVF analyses tile at ' +
          '512 m step, so this default OVERCOUNTS their tiles (and cost) ~4×. ' +
          'Pass the same analysisType you will pass to runArea.',
      })
    } else if (!TILING_SUPPORTED_TYPES.has(analysisType)) {
      // Same guard + message as runArea — preview must reject exactly what
      // runArea would reject.
      throw new Error(
        `Analysis type '${analysisType}' is not supported for tiling. ` +
          `Supported types: ${[...TILING_SUPPORTED_TYPES].sort().join(', ')}`,
      )
    }

    const tileSvc = new TileService({
      polygon: validated,
      analysisType,
      maxTilesOverride: opts?.maxTilesOverride,
    })
    const tileGrid = tileSvc.generateTilesForPolygon()
    const nonEmpty = getNonEmptyTiles(tileGrid)

    return {
      tileCount: nonEmpty.length,
      estimatedTimeS: nonEmpty.length * ESTIMATED_SECONDS_PER_TILE,
      estimatedCostTokens: nonEmpty.length * DEFAULT_TOKENS_PER_JOB,
    }
  }

  // -------------------------------------------------------------------------
  // previewAreaWithPricing -- tile count preview + live gateway pricing
  // -------------------------------------------------------------------------

  /**
   * Preview tiling for a polygon AND price it with the gateway's live public
   * pricing document (`GET /billing/pricing`).
   *
   * The tile count comes from the same local computation as `previewArea()`
   * (single source of truth); only the per-job token price is remote. When
   * the pricing fetch fails for ANY reason the method logs a warning and
   * falls back to the offline constant (`DEFAULT_TOKENS_PER_JOB`) with
   * `pricingSource: 'fallback'` — it never throws for pricing reasons.
   * Polygon-validation and unsupported-type errors still throw, exactly as
   * in `previewArea()`.
   *
   * @param polygon - A GeoJSON Polygon object.
   * @param opts.analysisType - Analysis type the preview should size for.
   * @param opts.maxTilesOverride - Optional override for the non-empty tile cap.
   * @param opts.forceRefresh - Bypass the 5-minute pricing cache.
   * @returns Preview with tile count, per-job token price, its source, and
   *   the pricing document version when resolved remotely.
   */
  async previewAreaWithPricing(
    polygon: unknown,
    opts: { analysisType: AnalysesName; maxTilesOverride?: number; forceRefresh?: boolean },
  ): Promise<AreaPreviewWithPricing> {
    const preview = this.previewArea(polygon, {
      analysisType: opts.analysisType,
      maxTilesOverride: opts.maxTilesOverride,
    })

    try {
      const pricing = await this.billing.getPricing({ forceRefresh: opts.forceRefresh })
      const tokensPerJob = resolveTokensPerJob(pricing, opts.analysisType)
      return {
        ...preview,
        estimatedCostTokens: preview.tileCount * tokensPerJob,
        tokensPerJob,
        pricingSource: 'remote',
        pricingVersion: pricing.version !== undefined ? String(pricing.version) : undefined,
      }
    } catch (error) {
      this.logger.warn({
        event: 'pricing_fetch_failed',
        message:
          'Failed to fetch gateway pricing; using offline fallback of ' +
          `${DEFAULT_TOKENS_PER_JOB} tokens/job`,
        error: error instanceof Error ? error.message : String(error),
      })
      // preview.estimatedCostTokens already used DEFAULT_TOKENS_PER_JOB.
      return {
        ...preview,
        tokensPerJob: DEFAULT_TOKENS_PER_JOB,
        pricingSource: 'fallback',
      }
    }
  }

  // -------------------------------------------------------------------------
  // runArea -- area-level job submission
  // -------------------------------------------------------------------------

  /**
   * Submit tiled analysis jobs over a polygon.
   *
   * Validates the polygon, generates tiles internally, optionally fetches
   * buildings per tile via the API, and submits jobs. Returns an AreaSchedule
   * for tracking and later merging.
   *
   * When `buildings` is provided (non-empty object), the SDK calls
   * `getBuildingsByTiles()` to retrieve per-tile building data from the
   * API with server-side spatial filtering. The `buildings` parameter
   * signals that building geometry context is needed for the analysis.
   *
   * @param input - Analysis input (template payload).
   * @param polygon - A GeoJSON Polygon object.
   * @param buildings - Building meshes keyed by identifier. When provided and non-empty,
   *   triggers per-tile building fetch via the API. Pass `undefined` to skip building injection.
   * @returns Schedule of submitted jobs.
   */
  async runArea(
    input: AnalysisInput,
    polygon: unknown,
    opts: RunAreaOptions = {},
  ): Promise<AreaSchedule> {
    const validated = validatePolygon(polygon)

    // Prepare payload first so analysisType is derived from the transform pipeline
    const { analysisType, serialized } = this.preparePayload(input)

    if (!TILING_SUPPORTED_TYPES.has(analysisType)) {
      throw new Error(
        `Analysis type '${analysisType}' is not supported for tiling. ` +
          `Supported types: ${[...TILING_SUPPORTED_TYPES].sort().join(', ')}`,
      )
    }

    // Generate tiles using analysis-type-specific config (wind: 50% overlap;
    // solar/UTCI/etc.: edge-to-edge).
    const tileSvc = new TileService({
      polygon: validated,
      analysisType,
      maxTilesOverride: opts.maxTilesOverride,
    })
    const tileGrid = tileSvc.generateTilesForPolygon()
    const nonEmpty = getNonEmptyTiles(tileGrid)
    const gridShape: [number, number] = [tileGrid.numRows, tileGrid.numCols]

    this.logger.info(`runArea: ${nonEmpty.length} non-empty tiles for polygon`)

    // Resolve buildings + vegetation + ground-materials into per-tile maps.
    // Mirrors Python SDK's `_area/_layers.py::resolve_layers`: each layer
    // gets a `{tileId: ...}` dict, with empty placeholders when the layer
    // is omitted or empty.
    //
    // Buildings have two entry shapes:
    //   1. `{ fetch: true }` sentinel — SDK pulls polygon-wide via
    //      `getBuildingsInArea` (deduped, polygon-bbox-SW frame).
    //   2. Flat `{ buildingId: { coordinates, ... } }` — caller-supplied,
    //      already in polygon-bbox-SW frame (matches Python's contract).
    //
    // Either way we run the result through `assignBuildingsToTiles` so a
    // building straddling a tile boundary lands in every tile it overlaps,
    // with full unclipped geometry. Pre-0.8.1 the SDK used per-tile
    // centroid-based fetch (`getBuildingsByTiles`) which silently
    // partitioned buildings 1:1 to tiles — boundary buildings invisible
    // to adjacent tiles, ~70% per-cell drift vs Python on wind. See
    // `docs/battle-scars.md` 2026-05-09 entry.
    let buildingsMap: Record<string, Record<string, unknown> | null> | undefined
    if (opts.buildings && Object.keys(opts.buildings).length > 0) {
      let flat: Record<string, Record<string, unknown>>
      if (
        Object.keys(opts.buildings).length === 1 &&
        (opts.buildings as Record<string, unknown>).fetch === true
      ) {
        const area = await this.buildings.getBuildingsInArea(validated)
        flat = area.buildings as unknown as Record<string, Record<string, unknown>>
      } else {
        flat = opts.buildings as Record<string, Record<string, unknown>>
      }
      const assigned = assignBuildingsToTiles(
        flat as unknown as Record<string, import('./tiling/transforms').BuildingData>,
        nonEmpty,
        { config: tileGrid.config },
      )
      buildingsMap = assigned as unknown as Record<string, Record<string, unknown> | null>
    } else if (
      serialized.geometries &&
      typeof serialized.geometries === 'object' &&
      Object.keys(serialized.geometries as Record<string, unknown>).length > 0
    ) {
      // Caller embedded buildings in input.geometries instead of passing
      // opts.buildings. Same contract as the opts flat-map shape: dotbim
      // mesh per building in polygon-bbox-SW frame. Slice per tile so each
      // tile only receives the buildings overlapping its context bbox, then
      // clear the shared dict so clonePayloadForTile doesn't deep-copy it
      // into every tile (memory + wasted CPU) before per-tile injection
      // overwrites it at the submit site below.
      const flat = serialized.geometries as Record<
        string,
        import('./tiling/transforms').BuildingData
      >
      const assigned = assignBuildingsToTiles(flat, nonEmpty, {
        config: tileGrid.config,
      })
      buildingsMap = assigned as unknown as Record<string, Record<string, unknown> | null>
      serialized.geometries = {}
    }
    // Extract inline `ground-materials` from the payload. Without this hop,
    // payload-embedded ground materials skip validateGroundMaterialKeys + the
    // per-tile properties.material stamp, and instead get deep-cloned verbatim
    // into every tile via clonePayloadForTile — silently falling back to
    // emissivity 0.97 on the server. The field is cleared from `serialized`
    // either way so the per-tile injection (already wired through
    // groundMaterialsMap below) is the only path that delivers them.
    // Mirrors Python sdk.py:524 (#143).
    let effectiveGroundMaterials = opts.groundMaterials
    const inlineGm = serialized['ground-materials'] as
      | Record<string, { features?: Array<Record<string, unknown>> }>
      | undefined
    if (inlineGm && Object.keys(inlineGm).length > 0) {
      if (!effectiveGroundMaterials) {
        effectiveGroundMaterials = inlineGm
      }
      serialized['ground-materials'] = undefined
    }
    const layers = resolveLayers(tileGrid, {
      vegetation: opts.vegetation,
      groundMaterials: effectiveGroundMaterials,
    })
    const vegetationMap = layers.vegetationMap
    const groundMaterialsMap = layers.groundMaterialsMap

    // Build per-tile payloads and submit
    const hash = await configHash(serialized)

    const jobs = new Map<string, import('./tiling/types').AreaJob>()
    const tilePositions: Array<{ row: number; col: number; tileId: string }> = []
    const failedSubmissions: string[] = []
    // Shared abort flag: set to 402 on the first InsufficientCreditsError so
    // not-yet-started pLimit slots are skipped. In-flight slots complete
    // normally (Promise.all still awaits them). Mirrors Python SDK's
    // `submission_abort_status` semantics — 402 is account-global.
    let submissionAbortStatus: number | null = null

    // retry_from filter — only resubmit tiles whose IDs match the
    // failed_submissions list of a prior schedule. Matches Python's
    // `retry_tile_ids` filter inside `_submit_single_payload`.
    const retryTileIds: Set<string> | null = opts.retryFrom
      ? new Set(opts.retryFrom.failedSubmissions)
      : null

    // Submit tiles in parallel, capped at MAX_PARALLEL_SUBMISSIONS to stay
    // under the Workers subrequest budget. Mirrors Python SDK's
    // ThreadPoolExecutor-based parallel submit (was sequential before).
    const limit = pLimit(opts.maxWorkers ?? MAX_PARALLEL_SUBMISSIONS)
    // Pre-compute the row/col/tileId triples in deterministic grid order
    // so `tilePositions` stays stable regardless of submit completion order
    // (Python preserves grid order; concurrent push would otherwise scramble it).
    for (const { row, col, tile } of nonEmpty) {
      tilePositions.push({ row, col, tileId: tile.tileId })
    }
    const submitTasks = nonEmpty.map(({ row, col, tile }) =>
      limit(async () => {
        // Abort flag set by an earlier 402 — skip this tile without submitting,
        // but record it as a failed submission so `failedSubmissions` is complete
        // and `retry_from=` can resubmit it (mirrors Python `_submission.py`,
        // which appends the tile to failed_submissions when the abort event is set).
        if (submissionAbortStatus !== null) {
          failedSubmissions.push(tile.tileId)
          return
        }

        if (retryTileIds && !retryTileIds.has(tile.tileId)) return

        const cloned = clonePayloadForTile(serialized, tile, analysisType)

        // Per-tile layer injection (matches Python `_area/_submission.py`).
        if (buildingsMap && tile.tileId in buildingsMap && buildingsMap[tile.tileId] !== null) {
          cloned.geometries = buildingsMap[tile.tileId]
        }
        if (
          vegetationMap[tile.tileId] &&
          Object.keys(vegetationMap[tile.tileId]).length > 0
        ) {
          cloned.vegetation = vegetationMap[tile.tileId]
        }
        if (
          groundMaterialsMap[tile.tileId] &&
          Object.keys(groundMaterialsMap[tile.tileId]).length > 0
        ) {
          // Server expects the kebab-case alias `ground-materials` — the
          // rest of `cloned` was already produced by `serializeToKebab`,
          // so writing camelCase here would not match the Pydantic alias
          // and the field gets silently ignored, dropping all materials.
          // `geometries` and `vegetation` are single-word so kebab == camel
          // and they don't have this hazard; any future multi-word per-tile
          // field needs the same treatment.
          cloned['ground-materials'] = groundMaterialsMap[tile.tileId]
        }

        try {
          const job = await submitWithRetry(
            // Forward webhook config to every tile (#48). RunAreaOptions
            // advertises these; without this they were silently dropped and
            // webhooks never fired for any area run. jobs.submit only writes
            // the wire fields when defined, so passing undefined is a no-op.
            () =>
              this.jobs.submit(analysisType, cloned, {
                webhookUrl: opts.webhookUrl,
                webhookEvents: opts.webhookEvents,
              }),
            this.logger,
            tile.tileId,
          )
          const initialStatus =
            job.status === JobStatus.Succeeded
              ? ('completed' as const)
              : job.status === JobStatus.Failed
                ? ('failed' as const)
                : job.status === JobStatus.Running
                  ? ('running' as const)
                  : ('pending' as const)
          jobs.set(tile.tileId, {
            tileId: tile.tileId,
            row,
            col,
            jobId: job.jobId,
            status: initialStatus,
            result: undefined,
            error: undefined,
          })
        } catch (error) {
          if (error instanceof InsufficientCreditsError) {
            // 402 is account-global — abort remaining not-yet-started tiles.
            submissionAbortStatus = 402
            this.logger.warn(
              `runArea: insufficient credits (402); aborting remaining tile submissions`,
            )
          } else {
            this.logger.warn(`runArea: failed to submit job for tile ${tile.tileId}: ${error}`)
          }
          failedSubmissions.push(tile.tileId)
          jobs.set(tile.tileId, {
            tileId: tile.tileId,
            row,
            col,
            status: 'failed',
            error: error instanceof Error ? error.message : String(error),
          })
        }
      }),
    )
    await Promise.all(submitTasks)

    // Freeze the schedule structurally — `jobs` becomes a Proxy that
    // throws on `set`/`delete`/`clear`, matching Python's
    // MappingProxyType. Per-job state (status, error, lastJobSnapshot)
    // is still mutated in place by `checkAreaState`.
    return freezeAreaSchedule({
      jobs,
      polygon: validated,
      configHash: hash,
      tilePositions,
      gridShape,
      analysisType,
      failedSubmissions,
      submissionAbortStatus,
    })
  }

  // -------------------------------------------------------------------------
  // checkAreaState -- poll all job statuses
  // -------------------------------------------------------------------------

  /**
   * Query all job statuses in an area schedule and compute aggregate state.
   *
   * @param schedule - The schedule to check.
   * @returns Current area state with status counts.
   */
  async checkAreaState(schedule: AreaSchedule): Promise<AreaState> {
    if (schedule.jobs.size === 0) {
      return computeAreaState(schedule)
    }

    // Cap concurrent status queries at STATUS_MAX_WORKERS to match Python
    // _DEFAULT_MAX_WORKERS=5; uncapped Promise.all let 50-tile areas spray
    // 50 parallel GETs per poll round.
    const limit = pLimit(STATUS_MAX_WORKERS)

    const tasks: Promise<void>[] = []

    for (const [_tileId, areaJob] of schedule.jobs) {
      const jobId = areaJob.jobId

      // Skip tiles that already have terminal status and no jobId
      if (!jobId) {
        continue
      }

      // Skip already terminal jobs
      if (
        areaJob.status === 'completed' ||
        areaJob.status === 'failed' ||
        areaJob.status === 'skipped'
      ) {
        continue
      }

      tasks.push(limit(() => this.pollOneJobStatus(jobId, areaJob)))
    }

    await Promise.all(tasks)

    return computeAreaState(schedule)
  }

  /**
   * Query one job's status with per-call retry. Mirrors Python
   * `_polling.py::query_one`: up to STATUS_RETRY_MAX retries on
   * retryable errors (429 / 5xx / timeout), honoring `Retry-After` when
   * present; on terminal failure increments the cross-round wedge
   * counter and may flip the tile to `skipped`.
   */
  private async pollOneJobStatus(jobId: string, areaJob: AreaJob): Promise<void> {
    let lastError: unknown
    for (let attempt = 0; attempt <= STATUS_RETRY_MAX; attempt++) {
      try {
        const job = await this.jobs.getStatus(jobId)
        this.pollFailureCounts.delete(jobId)
        areaJob.lastJobSnapshot = job
        if (job.status === JobStatus.Succeeded) {
          areaJob.status = 'completed'
        } else if (job.status === JobStatus.Failed) {
          areaJob.status = 'failed'
          areaJob.error = job.error ?? 'Job failed'
        } else if (job.status === JobStatus.Running) {
          areaJob.status = 'running'
        } else if (job.status === JobStatus.Pending) {
          areaJob.status = 'pending'
        }
        return
      } catch (err) {
        lastError = err
        if (attempt < STATUS_RETRY_MAX && isRetryablePollError(err)) {
          const delay = computePollRetryDelay(attempt, err)
          this.logger.warn(
            `checkAreaState: job ${jobId} status query failed ` +
              `(attempt ${attempt + 1}/${STATUS_RETRY_MAX + 1}), retrying in ${delay.toFixed(2)}s: ` +
              `${err instanceof Error ? err.message : String(err)}`,
          )
          await new Promise((resolve) => setTimeout(resolve, delay * 1000))
          continue
        }
        break
      }
    }

    // Per-call retries exhausted (or first error was non-retryable).
    // Increment cross-round wedge counter; mark `skipped` if it trips.
    const count = (this.pollFailureCounts.get(jobId) ?? 0) + 1
    this.pollFailureCounts.set(jobId, count)
    this.logger.warn(
      `checkAreaState: status query failed for job ${jobId} ` +
        `(${count}/${MAX_CONSECUTIVE_POLL_FAILURES}): ` +
        `${lastError instanceof Error ? lastError.message : 'unknown'}`,
    )
    if (count >= MAX_CONSECUTIVE_POLL_FAILURES) {
      areaJob.status = 'skipped'
      areaJob.error = `Status query failed ${count} consecutive times; assuming unrecoverable`
      this.pollFailureCounts.delete(jobId)
    }
  }

  // -------------------------------------------------------------------------
  // mergeAreaJobs -- download and merge results
  // -------------------------------------------------------------------------

  /**
   * Download and merge results for succeeded jobs in a schedule.
   *
   * Can be called any time -- does NOT require all jobs to be terminal.
   * Uses stored tile positions and grid shape from the schedule.
   *
   * @param schedule - The schedule whose results to merge.
   * @returns Merged result with grid, failed_jobs, skipped_jobs.
   */
  async mergeAreaJobs(
    schedule: AreaSchedule,
    opts?: {
      strategy?: 'default' | 'directional' | 'directional_blend'
      windDirectionDeg?: number
    },
  ): Promise<AreaResult> {
    const startTime = performance.now()
    const [numRows, numCols] = schedule.gridShape
    const strategy = opts?.strategy ?? 'default'
    const windDirectionDeg = opts?.windDirectionDeg

    // Mirror Python `_area/_merging.py:211` — directional strategies are
    // wind-speed-only. Fail fast before downloading anything.
    if (strategy !== 'default' && schedule.analysisType !== 'wind-speed') {
      throw new Error(
        `strategy=${JSON.stringify(strategy)} is only valid for wind-speed ` +
          `analyses; got analysisType=${JSON.stringify(schedule.analysisType)}.`,
      )
    }

    if (schedule.jobs.size === 0) {
      return {
        mergedGrid: new Float64Array(0),
        gridShape: [0, 0],
        failedJobs: [],
        skippedJobs: [],
        executionTime: 0,
        failedTiles: [],
        bounds: undefined,
      }
    }

    // First, check statuses
    await this.checkAreaState(schedule)

    // Identify which jobs to download, skip, or fail
    const succeededJobs: Array<{
      tileId: string
      jobId: string
      row: number
      col: number
      jobSnapshot?: Job
    }> = []
    const failedJobs: TileFailure[] = []
    const skippedJobs: string[] = []
    // Track API-side job IDs for failure/skipped tiles too — AreaRunError
    // returns these to the caller so they can re-poll or display links.
    // Fall back to tileId when no jobId exists (e.g. submission-stage
    // failures that never reached the server). Mirrors Python's
    // `AreaRunError.failed_jobs` which holds server-issued job IDs.
    const failedJobIds: string[] = []
    const skippedJobIds: string[] = []
    // Per-tile failure records classified by phase (#158). Built after the
    // download pass with first-seen dedup and priority
    // submit > compute > download > skipped. Kept separate from the existing
    // failedJobs/skippedJobs (which stay unchanged for back-compat).
    const downloadFailures: Array<{ tileId: string; row: number; col: number; error: string }> = []
    const skippedTileRecords: Array<{ tileId: string; row: number; col: number }> = []

    for (const [tileId, areaJob] of schedule.jobs) {
      const jobId = areaJob.jobId
      if (areaJob.status === 'completed' && jobId) {
        succeededJobs.push({
          tileId,
          jobId,
          row: areaJob.row,
          col: areaJob.col,
          jobSnapshot: areaJob.lastJobSnapshot as Job | undefined,
        })
      } else if (areaJob.status === 'failed') {
        failedJobs.push({
          tileId,
          row: areaJob.row,
          col: areaJob.col,
          error: areaJob.error ?? 'Job failed',
        })
        failedJobIds.push(jobId ?? tileId)
      } else {
        // pending, running, skipped -> NaN gap (non-terminal at merge time)
        skippedJobs.push(tileId)
        skippedJobIds.push(jobId ?? tileId)
        skippedTileRecords.push({ tileId, row: areaJob.row, col: areaJob.col })
      }
    }

    // Resolve the analysis-type-specific tiling config (wind vs solar/etc.)
    const tilingConfig = getTilingConfig(schedule.analysisType)
    const inferenceCells = tilingConfig.inferenceSizeCells

    // Download and decompress results for succeeded jobs
    const tileGrids: Array<{ row: number; col: number; grid: Float64Array }> = []

    const downloadPromises = succeededJobs.map(async ({ tileId, jobId, row, col, jobSnapshot }) => {
      try {
        const download = await submitWithRetry(
          () => this.jobs.downloadResults(jobId, { job: jobSnapshot }),
          this.logger,
          `download:${tileId}`,
        )
        const resultDict = this.jobs.decompress(download.content)
        const grid = extractGrid(resultDict)

        if (grid.length !== inferenceCells * inferenceCells) {
          this.logger.warn(
            `mergeAreaJobs: tile ${tileId} has unexpected grid size ${grid.length}, skipping`,
          )
          skippedJobs.push(tileId)
          skippedJobIds.push(jobId)
          // Succeeded job but grid extraction failed -> download phase (#158).
          downloadFailures.push({
            tileId,
            row,
            col,
            error: `unexpected grid size ${grid.length}`,
          })
          return
        }

        tileGrids.push({ row, col, grid })
      } catch (error) {
        this.logger.warn(`mergeAreaJobs: download failed for succeeded job ${jobId}: ${error}`)
        skippedJobs.push(tileId)
        skippedJobIds.push(jobId)
        // Succeeded job but result fetch failed permanently -> download phase.
        downloadFailures.push({
          tileId,
          row,
          col,
          error: `download failed: ${error instanceof Error ? error.message : String(error)}`,
        })
      }
    })

    await Promise.all(downloadPromises)

    // Mirror Python SDK: if every job failed/skipped and nothing succeeded,
    // surface AreaRunError instead of silently returning an all-NaN grid.
    if (
      tileGrids.length === 0 &&
      (failedJobs.length > 0 || skippedJobs.length > 0) &&
      schedule.jobs.size > 0
    ) {
      throw new AreaRunError(
        `Area run produced no usable tiles: ${failedJobs.length} failed, ` +
          `${skippedJobs.length} skipped, 0 succeeded out of ${schedule.jobs.size}`,
        {
          // Server-issued job IDs (fallback to tileId for submission-stage
          // failures that never reached the server). Matches Python's
          // AreaRunError.failed_jobs contract.
          failedJobs: failedJobIds,
          skippedJobs: skippedJobIds,
          totalJobs: schedule.jobs.size,
        },
      )
    }

    // Merge using config-aware center-crop (matches Python SDK).
    let mergedGrid: Float64Array
    let gridShape: [number, number]

    if (tileGrids.length > 0 && numRows > 0 && numCols > 0) {
      const entries: TileGridEntry[] = tileGrids.map(({ row, col, grid }) => ({
        row,
        col,
        grid,
      }))
      const mergeResult = mergeTiles(entries, numRows, numCols, tilingConfig, {
        strategy,
        windDirectionDeg,
      })
      mergedGrid = mergeResult.grid
      gridShape = [mergeResult.height, mergeResult.width]
    } else {
      if (numRows > 0 && numCols > 0) {
        const [height, width] = mergedGridShape(numRows, numCols, tilingConfig)
        mergedGrid = new Float64Array(height * width)
        mergedGrid.fill(NaN)
        gridShape = [height, width]
      } else {
        mergedGrid = new Float64Array(0)
        gridShape = [0, 0]
      }
    }

    // Clip to polygon. Merged-grid cell (0, 0) corresponds to the polygon
    // bbox-SW corner (meter origin) — both for wind and solar tiling configs.
    // Tile (0,0) is centred at `(0.5 * step, 0.5 * step)` with inference size
    // `inferenceSize_m`; its SW inference corner sits at
    // `(0.5*step - inferenceSize/2, ...)`. After centre-crop, merged[0,0]
    // lands back at the polygon SW. Pre-0.8.1 TS passed
    // `[-step/2, -step/2]` here, shifting the polygon mask by a full step
    // and producing a ~half-tile NaN-mask offset versus Python on every
    // run — see bench/results/full SVF case for visual proof. Python never
    // had this offset (`_area/_merging.py` uses default origin).
    if (mergedGrid.length > 0) {
      const { polygonMeters } = projectPolygonToMeters(schedule.polygon)
      mergedGrid = clipToPolygon(
        mergedGrid,
        gridShape[0],
        gridShape[1],
        polygonMeters,
        [0, 0],
        tilingConfig.cellSizeM,
      )
    }

    // Classify per-tile failures by phase with first-seen dedup (#158).
    // Priority submit > compute > download > skipped — a tile that failed to
    // submit is reported once, under the earliest phase it hit.
    const failedTiles: TileFailure[] = []
    const seenFailedTiles = new Set<string>()
    const addFailedTile = (
      tileId: string,
      row: number,
      col: number,
      error: string,
      phase: TileFailurePhase,
    ): void => {
      if (seenFailedTiles.has(tileId)) return
      seenFailedTiles.add(tileId)
      failedTiles.push({ tileId, row, col, error, phase })
    }
    for (const tileId of schedule.failedSubmissions) {
      const job = schedule.jobs.get(tileId)
      // Prefer the real exception captured at submit time over the generic
      // placeholder — that message (e.g. "HTTP 413: payload too large") is the
      // actionable signal for a submission failure.
      addFailedTile(
        tileId,
        job?.row ?? -1,
        job?.col ?? -1,
        job?.error ?? 'job submission failed',
        TileFailurePhase.Submit,
      )
    }
    for (const f of failedJobs) {
      addFailedTile(f.tileId, f.row, f.col, f.error, TileFailurePhase.Compute)
    }
    for (const d of downloadFailures) {
      addFailedTile(d.tileId, d.row, d.col, d.error, TileFailurePhase.Download)
    }
    for (const s of skippedTileRecords) {
      addFailedTile(
        s.tileId,
        s.row,
        s.col,
        'job did not reach a terminal state',
        TileFailurePhase.Skipped,
      )
    }

    // True geographic extent of the merged grid (#122) — padded N/E to the
    // step boundary, so visualisers can place the bitmap without squashing.
    const bounds = computeGridBounds(schedule.polygon, numRows, numCols, tilingConfig)

    const elapsed = (performance.now() - startTime) / 1000

    return {
      mergedGrid,
      gridShape,
      failedJobs,
      skippedJobs,
      executionTime: elapsed,
      failedTiles,
      bounds,
    }
  }

  // -------------------------------------------------------------------------
  // runAreaAndWait -- area-level, blocking
  // -------------------------------------------------------------------------

  /**
   * Submit area jobs, poll until complete, merge and return results.
   *
   * @param input - Analysis input (template payload).
   * @param polygon - A GeoJSON Polygon object.
   * @param buildings - Building meshes keyed by identifier. When provided and non-empty,
   *   triggers per-tile building fetch. Pass `undefined` to skip.
   * @param maxWorkers - Reserved for future concurrency control. Currently unused.
   * @param opts - Optional polling configuration.
   * @returns Merged area result.
   * @throws Error if areaTimeout is reached before all jobs complete.
   */
  async runAreaAndWait(
    input: AnalysisInput,
    polygon: unknown,
    opts: RunAreaOptions & {
      /** Total area timeout in seconds. Default: 3600. */
      areaTimeout?: number
      /** Callback fired each polling round with the current area state. */
      onProgress?: (state: AreaState) => void
      /**
       * Merge strategy passed through to `mergeAreaJobs`. Default
       * `'default'` (centre-crop). `'directional'` / `'directional_blend'`
       * are wind-speed only and require `windDirectionDeg`.
       */
      strategy?: 'default' | 'directional' | 'directional_blend'
      /** Wind-from direction in degrees, required for directional strategies. */
      windDirectionDeg?: number
    } = {},
  ): Promise<AreaResult> {
    const areaTimeout = opts.areaTimeout ?? 3600
    const onProgress = opts.onProgress

    // Submit (forwards all layer / webhook / retry kwargs).
    const schedule = await this.runArea(input, polygon, opts)

    // Poll until complete
    const deadline = performance.now() + areaTimeout * 1000
    let attempt = 0

    while (true) {
      const state = await this.checkAreaState(schedule)

      if (onProgress) {
        try {
          onProgress(state)
        } catch {
          // Swallow callback errors
        }
      }

      if (state.isComplete) {
        break
      }

      // Check timeout before sleeping
      const remaining = (deadline - performance.now()) / 1000
      if (remaining <= 0) {
        throw new AreaTimeoutError(
          `Area analysis timed out after ${areaTimeout}s. ` +
            `State: ${state.completedCount}/${state.totalCount} completed, ` +
            `${state.failedCount} failed, ${state.runningCount} running`,
          { areaState: state },
        )
      }

      // Full jitter backoff: base=2, cap=60, floor=1.0
      const rawDelay = Math.min(POLL_BACKOFF_CAP, POLL_BACKOFF_BASE * 2 ** attempt)
      let delay = Math.max(POLL_BACKOFF_FLOOR, Math.random() * rawDelay)
      // Clamp to remaining time
      delay = Math.min(delay, remaining)

      await sleep(delay * 1000)
      attempt++
    }

    // Merge results
    return this.mergeAreaJobs(schedule, {
      strategy: opts.strategy,
      windDirectionDeg: opts.windDirectionDeg,
    })
  }
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms))
}
