/**
 * VegetationService — port of Python SDK's VegetationServiceClient.
 *
 * Three public methods:
 *   - getGeoJson(lat, lon, distance, source?)  — single point fetch
 *   - convertToMesh(featureCollection)         — DotBim mesh conversion
 *   - getArea(polygon, opts?)                  — parallel per-tile fetch +
 *                                                cross-tile deduplication
 */

import pLimit from 'p-limit'
import type { AuthResolver } from '../auth'
import { VegetationServiceError } from '../errors'
import { extractResponseBody, extractStatusCode, HttpClient } from '../http'
import type { Logger } from '../logger'
import { TileService } from '../tiling/tiles'
import { getNonEmptyTiles } from '../tiling/types'

export interface VegetationServiceConfig {
  /** Auth header resolver — supports apiKey + JWT (token / getToken). */
  getAuthHeaders: AuthResolver
  baseUrl: string
  logger: Logger
  /** Request timeout in ms; default 300_000 (5 min). */
  timeout?: number
  /** Bare gateway URL for big-payload presign. Threaded from InfraredClient. */
  gatewayBaseUrl?: string
  /** Lazy big-payload kill switch — re-resolved per call. */
  getBigPayloadEnabled?: () => boolean
  /** Lazy big-payload threshold (bytes) — re-resolved per call. */
  getBigPayloadThresholdBytes?: () => number
}

/** GeoJSON FeatureCollection — tree points returned by the API. */
export type GeoJsonFeatureCollection = {
  type?: string
  features?: Array<Record<string, unknown>>
  referencePoint?: [number, number]
  [key: string]: unknown
}

/** DotBim mesh as returned by `/convert/geojson-to-mesh`. */
export interface DotBimMesh {
  mesh_id: number
  coordinates: number[]
  indices?: number[]
}

/** Aggregated area vegetation result — mirrors Python `AreaVegetation`. */
export interface AreaVegetation {
  /**
   * Deduplicated GeoJSON features keyed by stable id (OSM id, OSM @id,
   * or rounded lat/lon fallback).
   */
  features: Record<string, Record<string, unknown>>
  polygon: unknown
  totalTrees: number
  executionTime: number
  /**
   * Tile IDs whose vegetation fetch failed. The tile is treated as
   * no-vegetation (null result) so the pipeline continues. Mirrors Python
   * SDK `AreaVegetation.failed_tiles` (0.4.10).
   */
  failedTiles: string[]
}

export interface IVegetationService {
  getGeoJson(
    lat: number,
    lon: number,
    distance: number,
    source?: string,
  ): Promise<GeoJsonFeatureCollection | null>
  convertToMesh(featureCollection: GeoJsonFeatureCollection): Promise<DotBimMesh[]>
  getArea(
    polygon: unknown,
    opts?: {
      maxWorkers?: number
      maxTilesOverride?: number
    },
  ): Promise<AreaVegetation>
}

/**
 * Tile fetch radius — matches Python: `ceil(sqrt(2) * 256)`. The √2
 * factor covers the diagonal so the circular fetch around a tile centre
 * fully contains the 256×256m inner crop.
 */
const TILE_FETCH_DISTANCE_M = Math.ceil(Math.sqrt(2) * 256)

/** Default per-tile vegetation source (same as Python's `_get_geojson`). */
const DEFAULT_SOURCE = 'fgb'

export class VegetationService implements IVegetationService {
  private httpClient: HttpClient
  private logger: Logger

  constructor(config: VegetationServiceConfig) {
    this.httpClient = new HttpClient({
      getAuthHeaders: config.getAuthHeaders,
      baseUrl: config.baseUrl,
      logger: config.logger,
      timeout: config.timeout ?? 300_000,
      gatewayBaseUrl: config.gatewayBaseUrl,
      getBigPayloadEnabled: config.getBigPayloadEnabled,
      getBigPayloadThresholdBytes: config.getBigPayloadThresholdBytes,
    })
    this.logger = config.logger
  }

  async getGeoJson(
    lat: number,
    lon: number,
    distance: number,
    source: string = DEFAULT_SOURCE,
  ): Promise<GeoJsonFeatureCollection | null> {
    try {
      const data = await this.httpClient.get<GeoJsonFeatureCollection>('/gis/vegetation', {
        latitude: lat,
        longitude: lon,
        distance,
        source,
      })
      if (!data || !data.features || data.features.length === 0) return null
      return data
    } catch (err) {
      // Throw typed error matching Python's `VegetationServiceClient`,
      // so callers can catch by class and inspect status_code/responseBody.
      // The previous behaviour silently returned `null` on every failure,
      // hiding 500s from the caller.
      throw new VegetationServiceError(
        `Vegetation fetch failed at (${lat}, ${lon}): ${err instanceof Error ? err.message : String(err)}`,
        {
          statusCode: extractStatusCode(err),
          responseBody: extractResponseBody(err),
          operation: 'getGeoJson',
        },
      )
    }
  }

  async convertToMesh(featureCollection: GeoJsonFeatureCollection): Promise<DotBimMesh[]> {
    const featureCount = (featureCollection.features ?? []).length
    this.logger.debug(`POST /convert/geojson-to-mesh (${featureCount} features)`)
    try {
      // serializeNames:false — send the FeatureCollection VERBATIM (Python's
      // `post_with_big_payload(url, feature_collection)` does no transform).
      // The default kebab serializer rewrites the required top-level
      // `referencePoint` → `reference-point`, which the server rejects with
      // 422 "missing referencePoint".
      //
      // gzip:true — tree-heavy areas exceed 5 MiB raw JSON. The server does
      // NOT resolve the `$ref` envelope on this endpoint (verified: it 422s
      // validating the `{$ref}` wrapper as the FC), so bigPayload would fail.
      // It DOES gunzip a standard `Content-Encoding: gzip` body (verified: 200)
      // and geometry compresses ~18×, so gzipping keeps even large FCs inline.
      const meshes = await this.httpClient.post<DotBimMesh[]>(
        '/convert/geojson-to-mesh',
        featureCollection,
        { gzip: true, serializeNames: false },
      )
      return Array.isArray(meshes) ? meshes : []
    } catch (err) {
      throw new VegetationServiceError(
        `geojson-to-mesh failed (${featureCount} features): ${err instanceof Error ? err.message : String(err)}`,
        {
          statusCode: extractStatusCode(err),
          responseBody: extractResponseBody(err),
          operation: 'convertToMesh',
        },
      )
    }
  }

  async getArea(
    polygon: unknown,
    opts: { maxWorkers?: number; maxTilesOverride?: number } = {},
  ): Promise<AreaVegetation> {
    const t0 = performance.now()
    const maxWorkers = opts.maxWorkers ?? 10

    // 1. Generate tiles (vegetation always uses wind-style 256m step — same
    //    overlap shape as buildings, since it injects at the same wire layer).
    const svc = new TileService({
      polygon,
      maxTilesOverride: opts.maxTilesOverride,
    })
    const grid = svc.generateTilesForPolygon()
    const nonEmpty = getNonEmptyTiles(grid)
    this.logger.info(
      `getArea: ${nonEmpty.length} non-empty tile(s); fetching vegetation in parallel ` +
        `(up to ${maxWorkers} workers)`,
    )

    // 2. Fetch GeoJSON per tile centroid in parallel (p-limit caps concurrency).
    // A single failed tile shouldn't kill the whole pipeline — log and treat
    // as no-vegetation for that tile, matching Python's `executor.execute`
    // which collects failures separately.
    const limit = pLimit(maxWorkers)
    const failedTiles: string[] = []
    const fetchTasks = nonEmpty.map(({ tile }) =>
      limit(async () => {
        try {
          return await this.getGeoJson(
            tile.centroid.latitude,
            tile.centroid.longitude,
            TILE_FETCH_DISTANCE_M,
          )
        } catch (err) {
          this.logger.warn(`Vegetation tile ${tile.tileId} failed: ${err}`)
          failedTiles.push(tile.tileId)
          return null
        }
      }),
    )
    const results = await Promise.all(fetchTasks)

    // 3. Deduplicate features across overlapping tiles
    const dedup = dedupVegetationFeatures(results)

    const elapsed = (performance.now() - t0) / 1000
    this.logger.info(
      `Vegetation pipeline: ${Object.keys(dedup).length} unique trees, ` +
        `${nonEmpty.length} tiles, ${elapsed.toFixed(1)}s`,
    )

    return {
      features: dedup,
      polygon,
      totalTrees: Object.keys(dedup).length,
      executionTime: elapsed,
      failedTiles,
    }
  }
}

// ---------------------------------------------------------------------------
// Dedup — mirrors Python `vegetation/dedup.py`
// ---------------------------------------------------------------------------

/**
 * Extract a dedup key from a GeoJSON Feature.
 *
 * Order: feature.id → properties.osmid → properties["@id"] → rounded (lat, lon).
 */
function featureDedupKey(feature: Record<string, unknown>): string {
  const fid = feature.id
  if (fid !== undefined && fid !== null) return String(fid)

  const props = (feature.properties as Record<string, unknown> | undefined) ?? {}
  const osmid = props.osmid ?? props['@id']
  if (osmid !== undefined && osmid !== null) return String(osmid)

  // Geometry-based fallback — round to 6 decimal places to match Python's
  // `_feature_dedup_key` (vegetation/dedup.py). 6dp ≈ 0.11m at the equator,
  // well below the threshold where two distinct trees would collide.
  const geom = feature.geometry as { coordinates?: [number, number] } | undefined
  const coords = geom?.coordinates
  if (coords && coords.length >= 2) {
    return `${coords[0].toFixed(6)},${coords[1].toFixed(6)}`
  }

  // Fallback — JSON-stringify the feature itself (worst case)
  return JSON.stringify(feature)
}

function dedupVegetationFeatures(
  results: ReadonlyArray<GeoJsonFeatureCollection | null>,
): Record<string, Record<string, unknown>> {
  const out: Record<string, Record<string, unknown>> = {}
  for (const fc of results) {
    if (!fc || !fc.features) continue
    for (const feature of fc.features) {
      const key = featureDedupKey(feature)
      // Keep first-seen — overlapping tiles may differ on per-tile metadata
      // but the underlying tree is the same; Python does the same.
      if (!(key in out)) out[key] = feature
    }
  }
  return out
}

// Re-export the error from the central errors module so callers can do
// `import { VegetationServiceError } from 'infrared-sdk-ts'`.
export { VegetationServiceError }
