import type { AuthResolver } from '../auth'
import { HttpClient } from '../http'
import type { Logger } from '../logger'
import { WIND_TILING_CONFIG } from '../tiling/config'
import { TileExecutor, type TileJob, type TileJobResult } from '../tiling/executor'
import { TileService } from '../tiling/tiles'
import { getNonEmptyTiles, type TileGrid } from '../tiling/types'
import { validatePolygon } from '../tiling/validation'

/** Buildings are tiled with the wind config (256m step). */
const TILE_STEP_M = WIND_TILING_CONFIG.stepM

/**
 * Combine per-tile buildings dicts into one for visualization.
 *
 * Mirrors Python SDK's `merge_buildings`: all non-null values from
 * `buildingsMap` are merged into a single object. List-valued keys are
 * concatenated across tiles; scalar keys take the last-seen value.
 *
 * @param buildingsMap - tileId → buildings object (or null).
 * @returns Combined buildings object, or `{}` if every entry was null.
 */
export function mergeBuildings(
  buildingsMap: Record<string, Record<string, unknown> | null | undefined>,
): Record<string, unknown> {
  const nonNull = Object.values(buildingsMap).filter(
    (v): v is Record<string, unknown> => v !== null && v !== undefined,
  )
  if (nonNull.length === 0) return {}
  if (nonNull.length === 1) return nonNull[0]

  const merged: Record<string, unknown> = {}
  for (const bld of nonNull) {
    for (const [key, value] of Object.entries(bld)) {
      if (Array.isArray(value) && Array.isArray(merged[key])) {
        merged[key] = (merged[key] as unknown[]).concat(value)
      } else {
        merged[key] = value
      }
    }
  }
  return merged
}
import type {
  AreaBuildings,
  BuildingsConfig,
  BuildingsRequest,
  BuildingsResponse,
  BuildingsResponseData,
} from './schemas'

export interface BuildingsServiceConfig {
  /** Auth header resolver — supports apiKey + JWT (token / getToken). */
  getAuthHeaders: AuthResolver
  baseUrl: string
  logger: Logger
  /** Request timeout in milliseconds */
  timeout?: number
  /** Maximum number of retries for retryable errors. Default: 2 */
  maxRetries?: number
  /** Bare gateway URL for big-payload presign. Threaded from InfraredClient. */
  gatewayBaseUrl?: string
  /** Lazy big-payload kill switch — re-resolved per call. */
  getBigPayloadEnabled?: () => boolean
  /** Lazy big-payload threshold (bytes) — re-resolved per call. */
  getBigPayloadThresholdBytes?: () => number
}

/**
 * Interface for dependency injection and testing.
 */
export interface IBuildingsService {
  getBuildings(request: BuildingsRequest): Promise<BuildingsResponse>
  getBuildingsInArea(polygon: unknown, config?: BuildingsConfig): Promise<AreaBuildings>
  getBuildingsByTiles(
    tiles: TileGrid,
    config?: BuildingsConfig,
  ): Promise<Record<string, Record<string, unknown> | null>>
}

/**
 * Service for accessing building data.
 *
 * Supports single-tile requests via `getBuildings()`, area-based retrieval
 * with deduplication via `getBuildingsInArea()`, and composable tile-grid
 * retrieval via `getBuildingsByTiles()`.
 */
export class BuildingsService implements IBuildingsService {
  private httpClient: HttpClient
  private logger: Logger

  constructor(config: BuildingsServiceConfig) {
    this.httpClient = new HttpClient({
      getAuthHeaders: config.getAuthHeaders,
      baseUrl: config.baseUrl,
      logger: config.logger,
      timeout: config.timeout,
      maxRetries: config.maxRetries,
      gatewayBaseUrl: config.gatewayBaseUrl,
      getBigPayloadEnabled: config.getBigPayloadEnabled,
      getBigPayloadThresholdBytes: config.getBigPayloadThresholdBytes,
    })
    this.logger = config.logger
  }

  /**
   * Fetch 3D building data for a single tile.
   *
   * @param request - The buildings request with coordinates, size, and options.
   * @returns The buildings response with mesh data.
   *
   * @example
   * ```ts
   * const response = await client.buildings.getBuildings({
   *   coordinates: { latitude: 52.52, longitude: 13.405 },
   *   size: { x: 512, y: 512 },
   *   outputFormat: 'DotBim',
   * })
   * ```
   */
  async getBuildings(request: BuildingsRequest): Promise<BuildingsResponse> {
    try {
      this.logger.debug(
        `Fetching buildings for lat:${request.coordinates.latitude}, lon:${request.coordinates.longitude}`,
      )

      // The buildings endpoint uses camelCase, so we disable automatic kebab-case serialization.
      // bigPayload routes >5 MiB requests through the auto-switching $ref envelope flow
      // (Python parity: `BuildingsServiceClient` uses `post_with_big_payload`).
      return await this.httpClient.post<BuildingsResponse>('/buildings', request, {
        compress: request.compress,
        serializeNames: false,
        bigPayload: !request.compress,
      })
    } catch (error) {
      this.logger.error(`Failed to fetch buildings: ${error}`)
      throw error
    }
  }

  /**
   * Fetch and deduplicate buildings for a polygon area.
   *
   * Tiles the polygon, fetches buildings per tile in parallel via TileExecutor,
   * deduplicates by building key in deterministic grid order, and transforms
   * coordinates from tile-SW to polygon-bbox-SW frame.
   *
   * @param polygon - GeoJSON Polygon (validated internally).
   * @param config - Optional configuration for output format, compression, and progress.
   * @returns Deduplicated buildings with execution time.
   */
  async getBuildingsInArea(polygon: unknown, config?: BuildingsConfig): Promise<AreaBuildings> {
    const startTime = performance.now()
    const cfg = config ?? {}

    // Area methods require DotBim format for coordinate transforms and deduplication.
    // Other formats have different coordinate structures that are not compatible
    // with the flat [x,y,z,...] transform logic.
    if (cfg.outputFormat && cfg.outputFormat !== 'DotBim') {
      throw new Error(
        `getBuildingsInArea only supports outputFormat 'DotBim', got '${cfg.outputFormat}'`,
      )
    }

    // 1. Validate polygon
    const validated = validatePolygon(polygon)

    // 2. Generate tiles
    const tileSvc = new TileService({ polygon: validated })
    const tileGrid = tileSvc.generateTilesForPolygon()
    const nonEmptyTiles = getNonEmptyTiles(tileGrid)

    this.logger.info(`getBuildingsInArea: ${nonEmptyTiles.length} non-empty tiles`)

    // 3. Build tile jobs
    const jobs: TileJob<BuildingsTileData>[] = nonEmptyTiles.map(({ row, col, tile }) => ({
      tileId: tile.tileId,
      row,
      col,
      execute: async (signal: AbortSignal) => {
        const req: BuildingsRequest = {
          coordinates: {
            latitude: tile.centroid.latitude,
            longitude: tile.centroid.longitude,
          },
          size: { x: 512, y: 512 },
          returnBuildingIds: true,
          outputFormat: cfg.outputFormat ?? 'DotBim',
          compress: cfg.compress ?? false,
          optimizations: cfg.optimizations,
        }

        // Reuse the shared httpClient -- it has no mutable per-request state.
        // Per-request signal is threaded via options. bigPayload opts in to
        // the auto-switching $ref envelope flow above the threshold.
        const resp = await this.httpClient.post<BuildingsResponse>('/buildings', req, {
          compress: req.compress,
          serializeNames: false,
          signal,
          bigPayload: !req.compress,
        })

        // Throw on API-level failure so TileExecutor records it as failed
        if (!resp.success) {
          const errMsg = resp.error?.message ?? 'Buildings API returned success=false'
          throw new Error(errMsg)
        }

        return {
          buildings: resp.data.buildings ?? undefined,
          buildingIds: resp.data.buildingIds ?? undefined,
          success: resp.success,
        }
      },
    }))

    // 4. Execute via TileExecutor
    const executor = new TileExecutor<BuildingsTileData>({
      onProgress: cfg.onProgress,
    })

    const execResult = await executor.execute(jobs)

    if (execResult.failures.length > 0) {
      this.logger.warn(
        `getBuildingsInArea: ${execResult.failures.length} tile(s) failed, returning partial results`,
      )
    }

    // 5. Index results by tile_id for deterministic grid-order iteration
    const resultsByTile = new Map<string, TileJobResult<BuildingsTileData>>()
    for (const result of execResult.results) {
      resultsByTile.set(result.tileId, result)
    }

    // 6. Deduplicate buildings and buildingIds in grid order (row-major)
    const seenBuildingKeys = new Set<string>()
    const seenBuildingIds = new Set<number>()
    const dedupedBuildings: Record<string, import('../types').DotBimMesh> = {}
    const dedupedBuildingIds: number[] = []

    for (const { row, col, tile } of nonEmptyTiles) {
      const tileResult = resultsByTile.get(tile.tileId)
      if (!tileResult || !tileResult.success || !tileResult.result) {
        continue
      }

      const tileBuildings = tileResult.result.buildings
      const tileIds = tileResult.result.buildingIds

      // Compute tile-SW offset for coordinate transform
      // offset = col*256 - 128, row*256 - 128
      const offsetX = col * TILE_STEP_M - TILE_STEP_M / 2.0
      const offsetY = row * TILE_STEP_M - TILE_STEP_M / 2.0

      // Process buildings: dedup by key, transform coords
      if (tileBuildings && typeof tileBuildings === 'object') {
        for (const [bldgKey, bldgData] of Object.entries(tileBuildings)) {
          if (seenBuildingKeys.has(bldgKey)) {
            continue
          }

          if (!bldgData || typeof bldgData !== 'object') {
            this.logger.warn(`Skipping building ${bldgKey}: data is not an object`)
            continue
          }

          const rawCoords = (bldgData as Record<string, unknown>).coordinates
          if (!rawCoords || !Array.isArray(rawCoords)) {
            this.logger.warn(`Skipping building ${bldgKey}: missing or non-array coordinates`)
            continue
          }

          // Transform coords from tile-SW to polygon-bbox-SW
          // polygon_coord = tile_coord + offset
          // So we ADD offset (negate the subtraction)
          let transformed: number[]
          if (rawCoords.length > 0 && rawCoords.length % 3 === 0) {
            transformed = transformBuildingCoordinates(rawCoords as number[], -offsetX, -offsetY)
          } else {
            transformed = [...(rawCoords as number[])]
          }

          dedupedBuildings[bldgKey] = {
            mesh_id: ((bldgData as Record<string, unknown>).mesh_id as number) ?? 0,
            coordinates: transformed,
            indices: (bldgData as Record<string, unknown>).indices as number[] | undefined,
          }
          seenBuildingKeys.add(bldgKey)
        }
      }

      // Process building_ids: dedup
      if (tileIds) {
        for (const bid of tileIds) {
          if (!seenBuildingIds.has(bid)) {
            seenBuildingIds.add(bid)
            dedupedBuildingIds.push(bid)
          }
        }
      }
    }

    const elapsed = (performance.now() - startTime) / 1000

    return {
      buildings: dedupedBuildings,
      buildingIds: dedupedBuildingIds,
      totalBuildings: Object.keys(dedupedBuildings).length,
      executionTime: elapsed,
    }
  }

  /**
   * Fetch buildings for each non-empty tile in a pre-generated grid.
   *
   * Returns a flat `{tileId: buildings_dict | null}` mapping suitable for
   * composable usage. A `null` value means the fetch failed for that tile.
   *
   * @param tiles - Tile grid produced by TileService.generateTilesForPolygon().
   * @param config - Optional configuration for output format, compression, and progress.
   * @returns Map from tile ID to buildings dict, or null for failed tiles.
   */
  async getBuildingsByTiles(
    tiles: TileGrid,
    config?: BuildingsConfig,
  ): Promise<Record<string, Record<string, unknown> | null>> {
    const cfg = config ?? {}
    const nonEmptyTiles = getNonEmptyTiles(tiles)

    this.logger.info(`getBuildingsByTiles: ${nonEmptyTiles.length} non-empty tiles`)

    // Build tile jobs
    const jobs: TileJob<BuildingsTileData>[] = nonEmptyTiles.map(({ row, col, tile }) => ({
      tileId: tile.tileId,
      row,
      col,
      execute: async (signal: AbortSignal) => {
        const req: BuildingsRequest = {
          coordinates: {
            latitude: tile.centroid.latitude,
            longitude: tile.centroid.longitude,
          },
          size: { x: 512, y: 512 },
          returnBuildingIds: true,
          outputFormat: cfg.outputFormat ?? 'DotBim',
          compress: cfg.compress ?? false,
          optimizations: cfg.optimizations,
        }

        const resp = await this.httpClient.post<BuildingsResponse>('/buildings', req, {
          compress: req.compress,
          serializeNames: false,
          signal,
          bigPayload: !req.compress,
        })

        if (!resp.success) {
          const errMsg = resp.error?.message ?? 'Buildings API returned success=false'
          throw new Error(errMsg)
        }

        return {
          buildings: resp.data.buildings ?? undefined,
          buildingIds: resp.data.buildingIds ?? undefined,
          success: resp.success,
        }
      },
    }))

    // Execute via TileExecutor
    const executor = new TileExecutor<BuildingsTileData>({
      onProgress: cfg.onProgress,
    })

    const execResult = await executor.execute(jobs)

    // Build output dict: all tile IDs present, failed tiles -> null
    const output: Record<string, Record<string, unknown> | null> = {}

    for (const result of execResult.results) {
      if (result.success && result.result) {
        output[result.tileId] = (result.result.buildings as Record<string, unknown>) ?? null
      } else {
        output[result.tileId] = null
      }
    }

    // Mark failed tiles as null
    for (const failure of execResult.failures) {
      output[failure.tileId] = null
    }

    return output
  }
}

// ---------------------------------------------------------------------------
// Internal types
// ---------------------------------------------------------------------------

/** Internal data shape returned from per-tile building fetch. */
interface BuildingsTileData {
  buildings?: BuildingsResponseData['buildings']
  buildingIds?: BuildingsResponseData['buildingIds']
  success: boolean
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

/**
 * Transform building coordinates by subtracting offsets.
 *
 * Coordinates are flat `[x, y, z, x, y, z, ...]`. Subtracts offsetX from
 * each x and offsetY from each y. Z values are preserved.
 */
function transformBuildingCoordinates(
  coordinates: number[],
  offsetX: number,
  offsetY: number,
): number[] {
  const result = [...coordinates]
  const numVertices = Math.floor(result.length / 3)
  for (let i = 0; i < numVertices; i++) {
    result[i * 3] -= offsetX // x
    result[i * 3 + 1] -= offsetY // y
    // z (result[i*3+2]) is preserved
  }
  return result
}
