/**
 * Layer resolution for area-level orchestration — port of Python's
 * `_area/_layers.py` + the per-layer `assign_*_to_tiles` helpers from
 * `vegetation/dedup.py` and `ground_materials/dedup.py`.
 *
 * Public surface:
 *   - `tileSwOffset(row, col, config)` — tile SW corner in meters
 *     relative to the polygon bbox SW corner.
 *   - `assignVegetationToTiles(features, tiles, polygon, config)` —
 *     centroid-containment assignment.
 *   - `assignGroundMaterialsToTiles(layers, tiles)` — bbox-intersection
 *     assignment in lat/lon space.
 *   - `resolveLayers(...)` — single entry that produces the three
 *     `{tileId: ...}` maps consumed by the per-tile injection in
 *     `runArea`.
 */

import { type TilingConfig, WIND_TILING_CONFIG } from '../tiling/config'
import {
  type GeoJSONPolygon,
  METERS_PER_DEG_LAT,
  TILE_SIZE_M,
  type TileGrid,
} from '../tiling/types'
import { getNonEmptyTiles } from '../tiling/types'
import { arrayMin } from '../utils'
// Re-export the canonical implementation from tiling/transforms — the local
// copy that lived here previously (`col * stepM - halfStep`) was numerically
// wrong for solar config: halfStep = stepCells * cellSize / 2 = 256, so
// solar tile (col=1) computed `1 * 512 - 256 = 256` instead of Python's
// `(1 + 0.5) * 512 - 256 = 512`. For wind (step=256, inference=512) the two
// formulae happened to coincide; nobody noticed until the cross-SDK bench
// surfaced ~1% per-cell drift on daylight-availability with shadows showing
// up in tiles where they didn't belong (TS placed each tree in 4 tiles
// instead of 1 because tile bounds were shifted by 256m). v0.8.1 fix.
export { tileSwOffset } from '../tiling/transforms'
import { tileSwOffset } from '../tiling/transforms'

interface NonEmptyTile {
  row: number
  col: number
  tile: {
    tileId: string
    centroid: { latitude: number; longitude: number }
  }
}

function ringFromPolygon(polygon: unknown): Array<[number, number]> {
  const p = polygon as { coordinates?: Array<Array<[number, number]>> } | undefined
  return p?.coordinates?.[0] ?? []
}

/**
 * Assign GeoJSON vegetation features to tiles by centroid containment.
 *
 * Each feature is placed in every tile whose bounding box contains its
 * centroid (lon/lat). Returns `{tileId: {featKey: feature}}`. Features
 * with no centroid are skipped with a warning.
 *
 * Mirrors Python `vegetation/dedup.py::assign_vegetation_to_tiles`.
 */
export function assignVegetationToTiles(
  features: Record<string, Record<string, unknown>>,
  tiles: ReadonlyArray<NonEmptyTile>,
  polygon: GeoJSONPolygon,
  config: TilingConfig = WIND_TILING_CONFIG,
): Record<string, Record<string, Record<string, unknown>>> {
  const result: Record<string, Record<string, Record<string, unknown>>> = {}
  for (const { tile } of tiles) result[tile.tileId] = {}

  const ring = ringFromPolygon(polygon)
  if (ring.length === 0) return result

  const lons = ring.map((c) => c[0])
  const lats = ring.map((c) => c[1])
  const swLon = arrayMin(lons)
  const swLat = arrayMin(lats)

  // Pre-compute each tile's CONTEXT bbox (meters, relative to polygon SW
  // corner). Mirrors Python: inference area + `context_margin_m` on every
  // side (0m for wind, 77m for solar). Pre-0.8.1 TS used `TILE_SIZE_M` only
  // (no context expansion), so trees within the 77m solar margin were sent
  // to Python tiles but missed by TS — visible as a ring of red dots in the
  // bench diff heatmap concentrated around tile edges.
  const margin = (config.contextSizeM - config.inferenceSizeM) / 2.0
  const inf = config.inferenceSizeM
  const tileBounds: Array<{
    tileId: string
    swX: number
    swY: number
    neX: number
    neY: number
  }> = []
  for (const { row, col, tile } of tiles) {
    const [swX, swY] = tileSwOffset(row, col, config)
    tileBounds.push({
      tileId: tile.tileId,
      swX: swX - margin,
      swY: swY - margin,
      neX: swX + inf + margin,
      neY: swY + inf + margin,
    })
  }

  for (const [featKey, feature] of Object.entries(features)) {
    const geom = feature.geometry as { coordinates?: [number, number] } | undefined
    const coords = geom?.coordinates
    if (!coords || coords.length < 2) continue

    const [featLon, featLat] = coords
    // Convert centroid to meters relative to polygon SW (matches Python's
    // `_lonlat_to_meters` — cos uses the feature's own latitude).
    const cosLat = Math.max(Math.cos((featLat * Math.PI) / 180), 1e-6)
    const x = (featLon - swLon) * METERS_PER_DEG_LAT * cosLat
    const y = (featLat - swLat) * METERS_PER_DEG_LAT

    // Strict open interval — features exactly on a tile's NE boundary
    // belong to the next tile (matches Python parity, prevents
    // boundary-double-counting once both tiles have the same feature
    // through bbox membership).
    for (const tb of tileBounds) {
      if (x > tb.swX && x < tb.neX && y > tb.swY && y < tb.neY) {
        // Deep-copy per tile (Python uses `copy.deepcopy`) — defensive
        // against any downstream mutation that might leak across tiles
        // through a shared reference.
        result[tb.tileId][featKey] = structuredClone(feature)
      }
    }
  }

  return result
}

const UUID_RE =
  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i

// Material names the server-side Lambda emissivity table recognises. Unknown
// names are warned (not hard-errored) so the SDK does not need a version bump
// every time the server adds a material.
const KNOWN_MATERIAL_NAMES = new Set([
  'asphalt',
  'building',
  'concrete',
  'soil',
  'vegetation',
  'water',
])

/**
 * Validate ground-material layer keys before per-tile assignment.
 *
 * - Throws when any key is a UUID (the common BYO mistake of passing
 *   `{<feature_uuid>: FeatureCollection}` instead of `{<material_name>: FC}`).
 *   UUID keys silently produced emissivity 0.97 for every feature because the
 *   Lambda fell back to "unknown" — same outcome as omitting `material`
 *   property entirely.
 * - Warns when a key is not in the whitelist (`asphalt`, `concrete`, `soil`,
 *   `vegetation`, `water`); the call proceeds so newly server-supported
 *   materials work without an SDK bump.
 *
 * Mirrors Python `_area/_layers.py::_validate_ground_material_keys`.
 */
export function validateGroundMaterialKeys(
  layers: Record<string, unknown>,
): void {
  const keys = Object.keys(layers)
  const uuidKeys = keys.filter((k) => UUID_RE.test(k))
  if (uuidKeys.length > 0) {
    throw new Error(
      "groundMaterials keys must be material names (e.g. 'asphalt', " +
        "'vegetation', 'water', 'concrete', 'soil') — not UUIDs. " +
        `UUID keys found: ${JSON.stringify(uuidKeys)}. ` +
        'Use layer names from areaGm.layers directly.',
    )
  }
  const unknown = keys.filter((k) => !KNOWN_MATERIAL_NAMES.has(k))
  if (unknown.length > 0) {
    const known = Array.from(KNOWN_MATERIAL_NAMES).sort()
    // eslint-disable-next-line no-console
    console.warn(
      `groundMaterials contains unrecognised material names: ${JSON.stringify(unknown)}. ` +
        `Known names are: ${JSON.stringify(known)}. ` +
        'Server-side emissivity may default to 0.97 if not registered.',
    )
  }
}

/**
 * Assign ground-material features to tiles by lat/lon bbox intersection.
 *
 * Each emitted feature carries `properties.material = <layerName>` (shallow
 * copy of input, caller-supplied features not mutated). Without that stamp
 * the Lambda fell back to "unknown" → emissivity 0.97 for every cell
 * regardless of the layer's name.
 *
 * Returns `{tileId: {layerName: FeatureCollection}}` — layers with no
 * intersecting features are omitted from that tile's entry. Matches
 * Python's revised broadcasting behavior (10MB API gateway cap).
 *
 * Mirrors Python `ground_materials/dedup.py::assign_ground_materials_to_tiles`.
 */
export function assignGroundMaterialsToTiles(
  layers: Record<string, { features?: Array<Record<string, unknown>> }>,
  tiles: ReadonlyArray<NonEmptyTile>,
): Record<string, Record<string, { type: string; features: Array<Record<string, unknown>> }>> {
  const result: Record<
    string,
    Record<string, { type: string; features: Array<Record<string, unknown>> }>
  > = {}
  for (const { tile } of tiles) result[tile.tileId] = {}

  // Pre-compute each tile's lat/lon bbox (half-tile-size each cardinal direction)
  const tileBounds: Array<{
    tileId: string
    minLon: number
    minLat: number
    maxLon: number
    maxLat: number
  }> = []
  for (const { tile } of tiles) {
    const lat = tile.centroid.latitude
    const lon = tile.centroid.longitude
    const hlat = TILE_SIZE_M / 2 / METERS_PER_DEG_LAT
    const cosLat = Math.max(Math.cos((lat * Math.PI) / 180), 1e-6)
    const hlon = TILE_SIZE_M / 2 / (METERS_PER_DEG_LAT * cosLat)
    tileBounds.push({
      tileId: tile.tileId,
      minLon: lon - hlon,
      minLat: lat - hlat,
      maxLon: lon + hlon,
      maxLat: lat + hlat,
    })
  }

  for (const [layerName, fc] of Object.entries(layers)) {
    const features = fc.features ?? []
    if (features.length === 0) continue
    for (const feature of features) {
      const fbbox = featureBbox(feature)
      if (!fbbox) continue
      const [fminLon, fminLat, fmaxLon, fmaxLat] = fbbox
      for (const tb of tileBounds) {
        // Axis-aligned overlap test
        const overlaps =
          fmaxLon >= tb.minLon &&
          fminLon <= tb.maxLon &&
          fmaxLat >= tb.minLat &&
          fminLat <= tb.maxLat
        if (!overlaps) continue
        const tileLayers = result[tb.tileId]
        if (!(layerName in tileLayers)) {
          tileLayers[layerName] = { type: 'FeatureCollection', features: [] }
        }
        // Shallow-copy the feature and stamp properties.material = layerName.
        // Without the stamp, the Lambda emissivity table falls back to
        // "unknown" → 0.97 for every cell. Shallow-copying keeps the caller's
        // input untouched (the same feature may legitimately live in multiple
        // tiles and we must not mutate any of those references).
        const props = (feature.properties as Record<string, unknown> | undefined) ?? {}
        tileLayers[layerName].features.push({
          ...feature,
          properties: { ...props, material: layerName },
        })
      }
    }
  }

  return result
}

/**
 * Compute the axis-aligned lon/lat bbox of a GeoJSON feature.
 * Returns `null` if geometry has no extractable coordinates.
 */
function featureBbox(
  feature: Record<string, unknown>,
): [number, number, number, number] | null {
  const geom = feature.geometry as
    | { type?: string; coordinates?: unknown }
    | undefined
  if (!geom) return null
  const coords = geom.coordinates
  if (!coords) return null

  let minLon = Number.POSITIVE_INFINITY
  let minLat = Number.POSITIVE_INFINITY
  let maxLon = Number.NEGATIVE_INFINITY
  let maxLat = Number.NEGATIVE_INFINITY

  const visit = (v: unknown): void => {
    if (Array.isArray(v)) {
      // Leaf: [lon, lat] (or [lon, lat, alt])
      if (typeof v[0] === 'number' && typeof v[1] === 'number') {
        const [lon, lat] = v as [number, number]
        if (lon < minLon) minLon = lon
        if (lat < minLat) minLat = lat
        if (lon > maxLon) maxLon = lon
        if (lat > maxLat) maxLat = lat
        return
      }
      for (const child of v) visit(child)
    }
  }
  visit(coords)

  if (!Number.isFinite(minLon)) return null
  return [minLon, minLat, maxLon, maxLat]
}

/**
 * Single-entry helper for `runArea`: takes the user-supplied layer maps
 * (any of which may be undefined / empty) and produces the three
 * `{tileId: ...}` maps that the per-tile injection consumes.
 *
 * For every layer:
 *   - undefined / empty input → empty placeholder per tile (`{}`)
 *   - non-empty input → bbox-assigned per tile
 *
 * Mirrors Python `_area/_layers.py::resolve_layers`. Buildings pass
 * through as-is (caller-supplied per-tile mapping) — TS doesn't yet
 * have an `assignBuildingsToTiles` helper so callers either pre-build
 * the per-tile map or rely on the `BuildingsService.getBuildingsByTiles`
 * fetch path used downstream.
 */
export function resolveLayers(
  tileGrid: TileGrid,
  opts: {
    buildings?: Record<string, Record<string, unknown> | null | undefined>
    vegetation?: Record<string, Record<string, unknown>>
    groundMaterials?: Record<string, { features?: Array<Record<string, unknown>> }>
  },
): {
  buildingsMap: Record<string, Record<string, unknown> | null>
  vegetationMap: Record<string, Record<string, Record<string, unknown>>>
  groundMaterialsMap: Record<
    string,
    Record<string, { type: string; features: Array<Record<string, unknown>> }>
  >
} {
  // Python parity (eef3917): the grid MUST carry an active TilingConfig.
  // Throwing here prevents a future refactor from silently re-introducing
  // the wind-preset fallback that 00f5f97 fixed — every solar/UTCI/daylight
  // run was routing trees to the wrong tiles before that fix.
  if (!tileGrid.config) {
    throw new Error(
      'resolveLayers: tileGrid.config is required (was the grid produced by ' +
        'TileService.generateTilesForPolygon()?). Without it, vegetation/ground-' +
        'materials assignment falls back to wind config and silently corrupts ' +
        'solar/UTCI/daylight runs.',
    )
  }
  const config = tileGrid.config

  const nonEmpty = getNonEmptyTiles(tileGrid).map(({ row, col, tile }) => ({
    row,
    col,
    tile,
  }))

  // Buildings: caller provides a pre-built per-tile map (or undefined/empty
  // → empty placeholders). Buildings have a separate fetch path
  // (BuildingsService.getBuildingsByTiles) used by `runArea` when caller
  // passes a non-empty buildings hint.
  const buildingsMap: Record<string, Record<string, unknown> | null> = {}
  for (const { tile } of nonEmpty) buildingsMap[tile.tileId] = {}
  if (opts.buildings) {
    for (const [tileId, val] of Object.entries(opts.buildings)) {
      if (tileId in buildingsMap) buildingsMap[tileId] = val ?? {}
    }
  }

  // Forward the grid's active config so vegetation assignment uses the right
  // stride (256m for wind, 512m for solar). Python fix 00f5f97.
  const vegetationMap =
    opts.vegetation && Object.keys(opts.vegetation).length > 0
      ? assignVegetationToTiles(opts.vegetation, nonEmpty, tileGrid.polygon, config)
      : Object.fromEntries(nonEmpty.map(({ tile }) => [tile.tileId, {}]))

  let groundMaterialsMap: Record<
    string,
    Record<string, { type: string; features: Array<Record<string, unknown>> }>
  >
  if (opts.groundMaterials && Object.keys(opts.groundMaterials).length > 0) {
    validateGroundMaterialKeys(opts.groundMaterials)
    groundMaterialsMap = assignGroundMaterialsToTiles(opts.groundMaterials, nonEmpty)
  } else {
    groundMaterialsMap = Object.fromEntries(
      nonEmpty.map(({ tile }) => [tile.tileId, {}]),
    )
  }

  return { buildingsMap, vegetationMap, groundMaterialsMap }
}
